import React from 'react';
import { useState, useEffect, useRef, useReducer, useCallback, useMemo, memo } from "react";

/* ═══ Audio Unlock ═══ */
/**
 * Mobile browsers (iOS Safari, Android Chrome) block audio until
 * the user has interacted with the page. This function must be called
 * inside a user-gesture handler (click/touchstart) to unlock audio.
 * After the first call it becomes a no-op.
 */
let _audioUnlocked = false;
/* ─ window._safeSpeak: reliable one-shot TTS for Android ─ */
if (typeof window !== "undefined") {
  window._safeSpeak = function(text, lang, rate) {
    const synth = window.speechSynthesis;
    if (!synth || !text) return;
    try { synth.cancel(); } catch(_) {}
    setTimeout(function() {
    try { if (synth.paused) synth.resume(); } catch(_) {}
    const u = new SpeechSynthesisUtterance(text.trim().slice(0, 200));
    u.lang = lang || "en-US"; u.rate = rate || 0.9;
    try { const vv=synth.getVoices(); const v=vv.find(x=>x.lang.startsWith(u.lang)); if(v) u.voice=v; } catch(_){}
    synth.speak(u);
    }, 90);
  };
}

function unlockAudio() {
  if (_audioUnlocked) return;
  _audioUnlocked = true;
  try {
    // Only unlock Web Audio API context — do NOT call synth.speak() here
    // because a silent utterance would queue before our real one.
    // speechSynthesis is unlocked by the cancel()+speak() in speak() itself.
    const ctx = new (window.AudioContext || window.webkitAudioContext)();
    const buf = ctx.createBuffer(1, 1, 22050);
    const src = ctx.createBufferSource();
    src.buffer = buf;
    src.connect(ctx.destination);
    src.start(0);
    setTimeout(() => ctx.close(), 500);
  } catch (_) { /* sandbox - ignore */ }
}

/* ═══ useTTS.js ═══ */
/**
 * useTTS - Text-to-Speech hook
 * BUGS FIXED:
 *  - null guard on window.speechSynthesis (sandbox/Firefox)
 *  - voiceschanged event listener (NOT onvoiceschanged assignment)
 *  - mounted ref prevents setState after unmount
 *  - gender-aware voice selection
 */
function useTTS() {
  const [speaking,  setSpeaking]  = useState(false);
  const [supported, setSupported] = useState(false);
  const mounted    = useRef(true);
  const speakIdRef = useRef(0);
  const voicesRef  = useRef([]);

  useEffect(() => {
    mounted.current = true;
    const synth = typeof window !== "undefined" ? window.speechSynthesis : null;
    if (!synth) return;
    setSupported(true);

    const loadVoices = () => {
      const v = synth.getVoices();
      if (v.length) { voicesRef.current = v; }
    };
    loadVoices();
    synth.addEventListener("voiceschanged", loadVoices);
    // Aggressive polling: Android/iOS often fire late
    let tries = 0;
    const poll = setInterval(() => {
      tries++;
      const v = synth.getVoices();
      if (v.length) { voicesRef.current = v; }
      if (tries >= 20 || v.length > 0) clearInterval(poll);
    }, 100);

    return () => {
      mounted.current = false;
      clearInterval(poll);
      try { synth.removeEventListener("voiceschanged", loadVoices); } catch(_) {}
      try { synth.cancel(); } catch(_) {}
    };
  }, []);

  const pickVoice = useCallback((lang, gender) => {
    // Always re-query directly - voicesRef may be stale on first call
    const all = voicesRef.current.length
      ? voicesRef.current
      : (typeof window !== "undefined" ? (window.speechSynthesis?.getVoices() || []) : []);
    if (!all.length) return null;

    const langBase = lang.slice(0, 5);
    const langRoot = lang.slice(0, 2);
    const femRe  = /female|samantha|karen|victoria|moira|aria|jenny|zira|alice|allison|ava|joanna|kendra|kimberly|salli|ivy|olivia/i;
    const malRe  = /male|daniel|david|fred|rishi|mark|guy|aaron|brian|joey|matthew|justin|kevin|james/i;
    const re     = gender === "female" ? femRe : malRe;
    const byLang = v => v.lang && (v.lang.startsWith(langBase) || v.lang.startsWith(langRoot));
    const isHQ   = v => /google|natural|neural|enhanced|wavenet|studio|premium/i.test(v.name);

    return (
      all.find(v => byLang(v) && isHQ(v) && re.test(v.name)) ||
      all.find(v => byLang(v) && isHQ(v)) ||
      all.find(v => byLang(v) && re.test(v.name)) ||
      all.find(v => byLang(v)) ||
      all.find(v => /en/i.test(v.lang) && isHQ(v)) ||
      all.find(v => /en/i.test(v.lang)) ||
      null
    );
  }, []);

  const speak = useCallback((text, { lang = "en-US", rate = 0.95, pitch = 1, gender = "female" } = {}) => {
    const synth = typeof window !== "undefined" ? window.speechSynthesis : null;
    if (!synth || !text || !text.trim()) return;

    // Step 1: unlock audio pipeline (iOS/Android requirement)
    unlockAudio();

    const myId = ++speakIdRef.current;

    // Step 2: cancel() then speak() in same gesture — this IS valid on Android Chrome.
    // cancel() clears the queue (including the silent unlock utterance).
    // speak() must follow synchronously in the same call stack.
    try { synth.cancel(); } catch(_) {}

    // Safe string cleaning — NO lookbehind, NO \p{} (not supported in Sucrase)
    const clean = text
      .replace(/\*\*([^*]+)\*\*/g, "$1")
      .replace(/\*([^*]+)\*/g, "$1")
      .replace(/`([^`]+)`/g, "$1")
      .replace(/[#_~>\[\]]/g, "")
      .replace(/[\uD800-\uDFFF]/g, "")   // strip surrogate pairs (emojis)
      .replace(/\s{2,}/g, " ")
      .trim();
    if (!clean) return;

    // Safe chunking — NO lookbehind regex
    const MAX = 150;
    let chunks;
    if (clean.length <= MAX) {
      chunks = [clean];
    } else {
      chunks = [];
      let remaining = clean;
      while (remaining.length > MAX) {
        // Find last sentence boundary before MAX
        let cut = -1;
        for (let i = MAX; i >= 60; i--) {
          if (remaining[i] === '.' || remaining[i] === '!' || remaining[i] === '?') {
            cut = i + 1;
            break;
          }
        }
        if (cut === -1) cut = MAX;
        chunks.push(remaining.slice(0, cut).trim());
        remaining = remaining.slice(cut).trim();
      }
      if (remaining) chunks.push(remaining);
    }

    const doSpeak = () => {
      if (myId !== speakIdRef.current) return;
      let idx = 0;

      const speakChunk = () => {
        if (myId !== speakIdRef.current) { if (mounted.current) setSpeaking(false); return; }
        if (idx >= chunks.length)        { if (mounted.current) setSpeaking(false); return; }

        const utt = new SpeechSynthesisUtterance(chunks[idx]);
        utt.lang  = lang || "en-US";
        utt.rate  = Math.max(0.5, Math.min(2.0, rate  || 0.95));
        utt.pitch = Math.max(0.5, Math.min(2.0, pitch || 1.0));

        // Try to set voice — but don't fail if voices aren't loaded yet
        try {
          const v = pickVoice(lang, gender);
          if (v) utt.voice = v;
        } catch(_) {}

        if (idx === 0) {
          utt.onstart = () => { if (mounted.current && myId === speakIdRef.current) setSpeaking(true); };
        }
        let endFired = false;
        utt.onend = () => {
          if (endFired) return;
          endFired = true;
          idx++; speakChunk();
        };
        utt.onerror = (e) => {
          if (e.error === "interrupted" || e.error === "canceled") return;
          // On network/synthesis error, retry chunk once after 400ms
          if (!endFired && mounted.current && myId === speakIdRef.current) {
            endFired = true;
            setTimeout(() => {
              if (myId === speakIdRef.current) { endFired = false; speakChunk(); }
            }, 400);
          }
        };

        try {
          // Force resume if paused (Android Chrome quirk)
          if (synth.paused) { try { synth.resume(); } catch(_) {} }
          synth.speak(utt);
        }
        catch(_) { if (mounted.current) setSpeaking(false); }
      };

      speakChunk();

      // Android keepalive — speechSynthesis pauses after ~14s
      const ka = setInterval(() => {
        if (myId !== speakIdRef.current) { clearInterval(ka); return; }
        try { if (synth.paused && synth.speaking) synth.resume(); } catch(_) {}
        if (!synth.speaking) clearInterval(ka);
      }, 8000);
      setTimeout(() => clearInterval(ka), 120000);
    };

    // Call synchronously — Android Chrome requires speak() in user gesture chain
    // Do NOT delay with setTimeout — breaks gesture requirement on Android.
    // Resume paused synth first (Android background tab bug).
    try { if (window.speechSynthesis && window.speechSynthesis.paused) window.speechSynthesis.resume(); } catch(_) {}
    doSpeak();
  }, [pickVoice]);

  // Resume when tab becomes visible
  useEffect(() => {
    const synth = typeof window !== "undefined" ? window.speechSynthesis : null;
    if (!synth) return;
    const onVisible = () => { if (document.visibilityState === "visible" && synth.paused) synth.resume(); };
    document.addEventListener("visibilitychange", onVisible);
    return () => document.removeEventListener("visibilitychange", onVisible);
  }, []);

  const stop = useCallback(() => {
    speakIdRef.current++;
    if (mounted.current) setSpeaking(false);
    try {
      const synth = typeof window !== "undefined" ? window.speechSynthesis : null;
      if (synth) { synth.cancel(); }
    } catch(_) {}
  }, []);

  return { speak, stop, speaking, supported, voices: voicesRef.current, voiceCount: voicesRef.current.length, pickVoice };
}


/* ═══ useSTT.js ═══ */
/**
 * useSTT - Speech-to-Text hook
 * BUGS FIXED:
 *  - Explicit getUserMedia() permission request before starting
 *  - NotAllowedError caught and surfaced clearly
 *  - txRef pattern fixes stale-closure in handleStop callbacks
 *  - Proper cleanup on unmount
 *  - Browser support check
 */
function useSTT({ lang = "en-US" } = {}) {
  const [transcript, setTranscript] = useState("");
  const [interim,    setInterim]    = useState("");
  const [recording,  setRecording]  = useState(false);
  const [error,      setError]      = useState(null);
  const [supported,  setSupported]  = useState(false);

  const recRef     = useRef(null);
  const mounted    = useRef(true);
  const txRef      = useRef("");
  const silenceRef = useRef(null);
  const retryCount = useRef(0);     // prevents infinite restart loop
  const MAX_RETRY  = 3;

  useEffect(() => {
    mounted.current = true;
    const SR =
      typeof window !== "undefined"
        ? window.SpeechRecognition || window.webkitSpeechRecognition
        : null;
    setSupported(!!SR);
    return () => {
      mounted.current = false;
      clearTimeout(silenceRef.current);
      recRef.current?.abort();
    };
  }, []);

  // Sync txRef with state so callbacks always get latest value
  useEffect(() => {
    txRef.current = transcript;
  }, [transcript]);

  const start = useCallback(async () => {
    const SR =
      typeof window !== "undefined"
        ? window.SpeechRecognition || window.webkitSpeechRecognition
        : null;

    if (!SR) {
      setError("Speech recognition requires Chrome or Edge on desktop.");
      return;
    }

    // FIX: request mic permission explicitly for clear error messages
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      stream.getTracks().forEach(t => t.stop()); // Release - STT uses its own stream
    } catch (e) {
      if (!mounted.current) return;
      if (e.name === "NotAllowedError") {
        setError("Microphone blocked. Click the 🔒 icon in your address bar and allow mic.");
      } else if (e.name === "NotFoundError") {
        setError("No microphone found. Please connect one and try again.");
      } else {
        setError("Mic error: " + e.message);
      }
      return;
    }

    recRef.current = new SR();
    recRef.current.lang           = lang || "en-US";
    recRef.current.continuous     = true;   // FIX: keep listening - stop via silence or manual stop
    recRef.current.interimResults = true;

    recRef.current.onstart = () => {
      if (!mounted.current) return;
      retryCount.current = 0;  // clean start - reset retry counter
      setRecording(true);
      setError(null);
      setTranscript("");
      setInterim("");
      txRef.current = "";
    };

    recRef.current.onresult = (e) => {
      if (!mounted.current) return;
      let fin = "", inter = "";
      for (let i = e.resultIndex; i < e.results.length; i++) {
        const t = e.results[i][0].transcript;
        e.results[i].isFinal ? (fin += t + " ") : (inter += t);
      }
      if (fin) {
        setTranscript(prev => {
          const next = (prev + fin).trim();
          txRef.current = next;
          return next;
        });
        clearTimeout(silenceRef.current);
        silenceRef.current = setTimeout(() => { recRef.current?.stop(); }, 1500);
      }
      if (inter) {
        setInterim(inter);
        clearTimeout(silenceRef.current);
        silenceRef.current = setTimeout(() => { recRef.current?.stop(); }, 1500);
      }
    };

    recRef.current.onerror = (e) => {
      if (!mounted.current) return;
      clearTimeout(silenceRef.current);
      if (e.error === "aborted")   { setRecording(false); return; }
      if (e.error === "no-speech") { setRecording(false); setInterim(""); return; }
      if (e.error === "network") {
        setRecording(false);
        // Cap retries - prevents infinite restart loop on persistent network failure
        if (retryCount.current < MAX_RETRY) {
          retryCount.current++;
          setTimeout(() => { if (mounted.current) start(); }, 800 * retryCount.current);
        } else {
          retryCount.current = 0;
          setError("Connection lost. Check your internet and tap mic to retry.");
        }
        return;
      }
      const messages = {
        "not-allowed":         "Microphone blocked. Go to browser Settings → Site permissions → Microphone → Allow.",
        "audio-capture":       "Microphone unavailable. Close other apps using it and retry.",
        "service-not-allowed": "Speech service blocked. Use Chrome or Edge.",
      };
      setError(messages[e.error] || `Mic error: ${e.error}`);
      setRecording(false);
    };

    recRef.current.onend = () => {
      if (!mounted.current) return;
      clearTimeout(silenceRef.current);
      setRecording(false);
      setInterim("");
    };

    try {
      recRef.current.start();
    } catch (e) {
      if (mounted.current) setError("Could not start: " + e.message);
    }
  }, [lang]);

  const stop       = useCallback(() => { clearTimeout(silenceRef.current); recRef.current?.stop(); }, []);
  const abort      = useCallback(() => { clearTimeout(silenceRef.current); recRef.current?.abort(); }, []);
  const reset      = useCallback(() => {
    clearTimeout(silenceRef.current);
    recRef.current?.abort();
    setTranscript("");
    setInterim("");
    setError(null);
    txRef.current = "";
  }, []);

  // FIX: getLatest() always returns current transcript, avoiding stale closure
  const getLatest  = useCallback(() => txRef.current, []);

  return {
    transcript,
    interim,
    recording,
    error,
    supported,
    start,
    stop,
    abort,
    reset,
    getLatest,
  };
}

/* ═══ useVoiceChat.js ═══ */
/**
 * useVoiceChat - ChatGPT-style real-time voice conversation
 * Flow: speak → silence detected → AI reply → auto TTS → loop
 * 
 * Features:
 *  - continuous SpeechRecognition (never cuts off mid-sentence)
 *  - 1.5-second silence timer to auto-stop
 *  - onspeechend as secondary trigger
 *  - onSend(text) callback to send text to AI
 *  - Phases: idle | listening | thinking | speaking
 */
function useVoiceChat({ lang = "en-US", onTranscript, enabled = true } = {}) {
  const [phase,    setPhase]    = useState("idle");
  const [interim,  setInterim]  = useState("");
  const [final,    setFinal]    = useState("");
  const [error,    setError]    = useState(null);

  const recRef          = useRef(null);
  const silenceRef      = useRef(null);
  const mounted         = useRef(true);
  const txRef           = useRef("");
  const activeRef       = useRef(false);
  const sentRef         = useRef(false);   // BUG FIX: prevent double-send
  const onTranscriptRef = useRef(onTranscript); // BUG FIX: always-fresh callback ref

  // Keep ref in sync so stale closures always call the latest callback
  useEffect(() => { onTranscriptRef.current = onTranscript; }, [onTranscript]);

  useEffect(() => {
    mounted.current = true;
    return () => {
      mounted.current = false;
      clearTimeout(silenceRef.current);
      recRef.current?.abort();
    };
  }, []);

  const stopSilenceTimer = useCallback(() => {
    clearTimeout(silenceRef.current);
  }, []);

  // Uses onTranscriptRef - never stale, never causes re-creation of startListening
  const triggerSend = useCallback(() => {
    stopSilenceTimer();
    if (sentRef.current) return;           // already sent - guard
    const tx = txRef.current.trim();
    if (!tx || !mounted.current) return;
    sentRef.current = true;                // lock before async
    if (mounted.current) {
      setPhase("thinking");
      setFinal(tx);
      setInterim("");
    }
    recRef.current?.abort();
    activeRef.current = false;
    txRef.current = "";
    // Call via ref - always latest callback, no stale closure
    onTranscriptRef.current && onTranscriptRef.current(tx);
    // Reset sent guard after a safe delay
    setTimeout(() => { sentRef.current = false; }, 2000);
  }, [stopSilenceTimer]); // no onTranscript dep needed - use ref

  const resetSilenceTimer = useCallback(() => {
    stopSilenceTimer();
    silenceRef.current = setTimeout(triggerSend, 1500);
  }, [triggerSend, stopSilenceTimer]);

  const startListening = useCallback(async () => {
    if (activeRef.current || !enabled) return;
    const SR =
      typeof window !== "undefined"
        ? window.SpeechRecognition || window.webkitSpeechRecognition
        : null;
    if (!SR) { setError("Speech recognition requires Chrome or Edge."); return; }

    // Request mic permission
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      stream.getTracks().forEach(t => t.stop());
    } catch (e) {
      if (!mounted.current) return;
      setError(e.name === "NotAllowedError"
        ? "Mic blocked. Allow mic in browser settings."
        : "Mic error: " + e.message
      );
      return;
    }

    txRef.current = "";
    activeRef.current = true;

    const rec = new SR();
    rec.lang           = lang;
    rec.continuous     = true;    // KEY: don't stop mid-speech
    rec.interimResults = true;

    rec.onstart = () => {
      if (!mounted.current) return;
      setPhase("listening");
      setInterim("");
      setFinal("");
      setError(null);
      txRef.current = "";
    };

    // Store latest timers/callbacks in refs so rec event handlers are never stale
    const resetTimerRef  = { fn: resetSilenceTimer };
    const triggerRef     = { fn: triggerSend };
    const stopTimerRef   = { fn: stopSilenceTimer };

    rec.onresult = (e) => {
      if (!mounted.current) return;
      let fin = "", inter = "";
      for (let i = e.resultIndex; i < e.results.length; i++) {
        const t = e.results[i][0].transcript;
        if (e.results[i].isFinal) fin += t + " ";
        else inter += t;
      }
      if (fin) {
        txRef.current = (txRef.current + fin).trim();
        setInterim("");
        resetTimerRef.fn(); // restart silence countdown
      }
      if (inter) {
        setInterim(inter);
        resetTimerRef.fn(); // speech still going - reset timer
      }
    };

    rec.onspeechend = () => {
      if (!mounted.current) return;
      stopTimerRef.fn();
      setTimeout(() => triggerRef.fn(), 300);
    };

    rec.onerror = (e) => {
      if (!mounted.current || e.error === "aborted" || e.error === "no-speech") return;
      setError("Speech error: " + e.error);
      setPhase("idle");
      activeRef.current = false;
    };

    rec.onend = () => {
      activeRef.current = false;
      if (!mounted.current) return;
      stopTimerRef.fn();
    };

    recRef.current = rec;
    try { rec.start(); } catch (e) { setError("Cannot start: " + e.message); activeRef.current = false; }
  }, [lang, enabled, triggerSend, resetSilenceTimer, stopSilenceTimer]);

  const stopListening = useCallback(() => {
    stopSilenceTimer();
    recRef.current?.stop();
    activeRef.current = false;
    if (mounted.current) setPhase("idle");
  }, [stopSilenceTimer]);

  const setThinking = useCallback(() => {
    if (mounted.current) setPhase("thinking");
  }, []);

  const setSpeaking = useCallback(() => {
    if (mounted.current) setPhase("speaking");
  }, []);

  const setIdle = useCallback(() => {
    if (mounted.current) { setPhase("idle"); setInterim(""); setFinal(""); txRef.current = ""; }
  }, []);

  return {
    phase, interim, final, error,
    startListening, stopListening,
    setThinking, setSpeaking, setIdle,
    isListening: phase === "listening",
    isThinking:  phase === "thinking",
    isSpeaking:  phase === "speaking",
    isIdle:      phase === "idle",
  };
}

/* ═══ ApiService.js ═══ */
/**
 * ApiService.js
 * Central service for all AI API calls.
 *
 * SECURITY NOTE:
 * In production, NEVER call Anthropic directly from the browser.
 * Replace the fetch calls below with your backend endpoints:
 *   fetch("/api/ai/chat", { method:"POST", body:... })
 * The backend proxy now supports Gemini AI Studio.
 */

const MODEL = "gemini-1.5-pro";
const API   = "/api/ai";

const HEADERS = {
  "Content-Type": "application/json",
};

async function callClaude(system, prompt, maxTokens = 600) {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), 20000); // 20s timeout
  try {
    const res = await fetch(API, {
      method: "POST",
      headers: HEADERS,
      signal: controller.signal,
      body: JSON.stringify({
        model: MODEL,
        max_tokens: maxTokens,
        system,
        messages: [{ role: "user", content: prompt }],
      }),
    });
    if (res.status === 429) {
      return "";
    }
    if (!res.ok) {
      const body = await res.text().catch(() => "");
      throw new Error(`HTTP ${res.status} ${body}`);
    }
    const data = await res.json();
    const text = data.content?.[0]?.text?.trim() ?? "";
    return text;
  } catch (err) {
    if (err?.name === "AbortError") console.warn("[API] Request timed out");
    else console.error("[API]", err.message);
    return "";
  } finally {
    clearTimeout(timer);
  }
}

async function streamClaude(system, messages, maxTokens = 500) {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), 20000);
  try {
    const res = await fetch(API, {
      method: "POST",
      headers: HEADERS,
      signal: controller.signal,
      body: JSON.stringify({ model: MODEL, max_tokens: maxTokens, system, messages }),
    });
    if (res.status === 429) {
      return "The AI is busy right now. Please try again in a moment.";
    }
    if (!res.ok) {
      const body = await res.text().catch(() => "");
      throw new Error(`HTTP ${res.status} ${body}`);
    }
    const data = await res.json();
    return data.content?.[0]?.text?.trim() || "Sorry, I received an empty response. Please try again.";
  } catch (err) {
    if (err?.name === "AbortError") return "Request timed out. Please check your connection.";
    console.error("[API stream]", err.message);
    return "Sorry, I could not connect. Please try again.";
  } finally {
    clearTimeout(timer);
  }
}

// ── Translation ──────────────────────────────────────────────────
const LANG_LABELS = {
  ml:"Malayalam", hi:"Hindi", ta:"Tamil", te:"Telugu",
  ar:"Arabic",    fr:"French", de:"German", es:"Spanish",
  zh:"Chinese",   ja:"Japanese", ko:"Korean", pt:"Portuguese",
};

export async function translateText(text, targetLang) {
  const label = LANG_LABELS[targetLang] || "Malayalam";
  return callClaude(
    `You are a professional translator. Reply ONLY with the ${label} translation, nothing else.`,
    `Translate to ${label}: "${text}"`,
    120
  );
}

export async function detectLanguage(text) {
  return callClaude(
    "Language detector. Reply ONLY with the ISO 639-1 language code (e.g. ml, hi, en, ar). Nothing else.",
    `What language is this: "${text}"`,
    10
  );
}

// ── Dictionary ───────────────────────────────────────────────────
export // Levenshtein distance - used by Dictionary (similar words) and Practice (scoring)
function levenshtein(a, b) {
  const dp = Array.from({ length: a.length + 1 }, (_, i) =>
    Array.from({ length: b.length + 1 }, (_, j) => (i === 0 ? j : j === 0 ? i : 0))
  );
  for (let i = 1; i <= a.length; i++)
    for (let j = 1; j <= b.length; j++)
      dp[i][j] = a[i-1] === b[j-1]
        ? dp[i-1][j-1]
        : 1 + Math.min(dp[i-1][j], dp[i][j-1], dp[i-1][j-1]);
  return dp[a.length][b.length];
}

