// Free Dictionary API - no key needed
async function fetchFreeDictionary(word) {
  try {
    // AbortSignal.timeout not available in all Android WebViews - use Promise.race
    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), 6000);
    let res;
    try {
      res = await fetch(
        `https://api.dictionaryapi.dev/api/v2/entries/en/${encodeURIComponent(word.trim())}`,
        { signal: controller.signal }
      );
    } finally {
      clearTimeout(timer);
    }
    if (!res.ok) return null;

    const data = await res.json();
    if (!data || !Array.isArray(data) || data.length === 0) return null;
    const entry = data[0];
    if (!entry || typeof entry !== "object") return null;
    // API returns {title:"No Definitions Found"} for unknown words
    if (entry.title) return null;

    const meanings = Array.isArray(entry.meanings) ? entry.meanings : [];
    const meaning  = meanings[0] || {};
    const defs     = Array.isArray(meaning.definitions) ? meaning.definitions : [];
    const def      = defs[0] || {};
    if (!def.definition) return null;

    return {
      phonetic:  entry.phonetic
                 || (Array.isArray(entry.phonetics) ? entry.phonetics.find(p => p?.text)?.text : "")
                 || "",
      pos:       meaning.partOfSpeech || "",
      definition: def.definition,
      simple:    def.definition,
      examples:  def.example ? [def.example] : [],
      synonyms:  [
        ...(Array.isArray(def.synonyms)     ? def.synonyms     : []),
        ...(Array.isArray(meaning.synonyms) ? meaning.synonyms : []),
      ].slice(0, 4),
      antonyms: [
        ...(Array.isArray(def.antonyms)     ? def.antonyms     : []),
        ...(Array.isArray(meaning.antonyms) ? meaning.antonyms : []),
      ].slice(0, 4),
      cefr: "",
      tip:  "",
    };
  } catch (err) {
    if (err?.name === "AbortError") return null; // timeout - not a crash
    return null;
  }
}

// Currency detection
async function detectCurrency() {
  try {
    const res = await fetch("https://ipapi.co/json/");
    const data = await res.json();
    const map = { AE:"AED",IN:"INR",GB:"GBP",US:"USD",EU:"EUR",SA:"SAR",QA:"QAR",KW:"KWD",BH:"BHD",OM:"OMR",EG:"EGP",PK:"PKR",BD:"BDT",LK:"LKR",MY:"MYR",SG:"SGD",AU:"AUD",CA:"CAD" };
    return { code: map[data.country_code]||"USD", country: data.country_name||"", countryCode: data.country_code||"" };
  } catch { return { code:"USD", country:"", countryCode:"" }; }
}

// AED base prices → local currency approx rates
const AED_RATES = { AED:1, INR:22.5, USD:0.27, GBP:0.21, EUR:0.25, SAR:1.02, QAR:0.99, KWD:0.083, BHD:0.103, OMR:0.105, EGP:13.2, PKR:75, BDT:29.8, LKR:80, MYR:1.27, SGD:0.37, AUD:0.42, CAD:0.37 };

function convertPrice(aedPrice, currCode) {
  const rate = AED_RATES[currCode] || 0.27;
  return Math.ceil(aedPrice * rate);
}

async function lookupWord(word, targetLang = "ml") {
  const label = LANG_LABELS[targetLang] || "Malayalam";
  
  // 1. Check local dict first for instant results
  const localResult = LOCAL_DICT[word.toLowerCase()];
  if (localResult) {
    const translation = await translateText(word, targetLang).catch(()=>"");
    return { ...localResult, word, translation };
  }
  
  // 2. Try Free Dictionary API (no API key needed!)
  const freeResult = await fetchFreeDictionary(word);
  if (freeResult) {
    const translation = await translateText(word, targetLang).catch(()=>"");
    return { ...freeResult, word, translation };
  }
  
  const prompt = `Dictionary entry for "${word}". Return ONLY valid JSON (no markdown, no backticks):
{
  "phonetic": "/IPA/",
  "cefr": "A1|A2|B1|B2|C1|C2",
  "pos": "noun|verb|adjective|adverb|etc",
  "definition": "clear English definition in one sentence",
  "simple": "explain like A2 level learner",
  "examples": ["natural example sentence 1", "natural example sentence 2"],
  "synonyms": ["word1", "word2", "word3"],
  "antonyms": ["word1", "word2"],
  "translation": "translation in ${label}",
  "tip": "usage tip for ${label} speakers"
}`;

  const raw = await callClaude(
    "Expert English dictionary. Return valid JSON only. No markdown, no backticks.",
    prompt,
    500
  );
  if (!raw?.trim()) return null;
  try {
    // Strip markdown fences the model sometimes adds despite instructions
    const cleaned = raw.split("```json").join("").split("```").join("").trim();
    const parsed  = JSON.parse(cleaned);
    if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) return null;
    // Require at least a definition
    if (!parsed.definition && !parsed.meaning) return null;
    // Coerce - API sometimes returns string for list fields
    if (!Array.isArray(parsed.examples)) parsed.examples = parsed.examples ? [String(parsed.examples)] : [];
    if (!Array.isArray(parsed.synonyms)) parsed.synonyms = [];
    if (!Array.isArray(parsed.antonyms)) parsed.antonyms = [];
    // Normalise field name difference
    if (!parsed.definition && parsed.meaning) parsed.definition = parsed.meaning;
    if (!parsed.simple) parsed.simple = parsed.definition;
    return parsed;
  } catch {
    return null;
  }
}

// ── Conversation generator ───────────────────────────────────────
export async function generateConversation(topic, level) {
  const prompt = `Generate a realistic ${level} English conversation about "${topic}".
Exactly 8 lines, alternating speakers A and B.
Return ONLY a JSON array (no markdown):
[
  {"speaker":"A","text":"...","note":"short grammar/vocab tip"},
  ...
]`;
  const raw = await callClaude(
    "English teacher. Return valid JSON arrays only. No markdown.",
    prompt,
    800
  );
  try {
    const parsed = JSON.parse(raw.split("```json").join("").split("```").join("").trim());
    return Array.isArray(parsed) ? parsed : [];
  } catch {
    return [];
  }
}

// ── AI Chatbot ───────────────────────────────────────────────────
export async function chatWithAI(messages, systemPrompt) {
  const history = messages
    .slice(-10)
    .map(m => ({ role: m.role, content: m.content }));
  return streamClaude(systemPrompt, history, 600);
}

// ── Pronunciation feedback ───────────────────────────────────────
export async function getPronunciationFeedback(targetText, spokenText) {
  const prompt = `Target sentence: "${targetText}"
User said: "${spokenText}"
Give 2-sentence pronunciation feedback. Be specific and encouraging. 
Mention 1 thing done well and 1 thing to improve.`;
  return callClaude(
    "English pronunciation coach. Be brief, specific, encouraging.",
    prompt,
    180
  );
}

// ── Grammar lesson ───────────────────────────────────────────────
export async function getGrammarLesson(topic, level) {
  const prompt = `Teach "${topic}" grammar for ${level} English learners.
Include:
1. Core rule (1-2 sentences)
2. Formula/pattern (e.g. Subject + has/have + past participle)
3. Three ✅ correct examples
4. Two ❌ common mistakes with corrections
5. One 💡 tip for Malayalam/South Asian speakers

Keep under 200 words. Use clear formatting.`;
  return callClaude(
    "Expert English grammar teacher. Be clear and practical. Use ✅ and ❌ examples.",
    prompt,
    450
  );
}

// ── Vocabulary AI generator ──────────────────────────────────────
export async function generateVocabWords(level, existingWords = [], count = 50) {
  const existing = existingWords.slice(-20).join(", ");
  const prompt = `Generate ${count} useful ${level} English vocabulary words NOT in: [${existing}].
Return ONLY a JSON array (no markdown):
[
  {
    "word": "...",
    "pos": "noun|verb|adjective|adverb|phrase",
    "meaning": "one-sentence definition",
    "example": "natural example sentence",
    "translation": "Malayalam translation",
    "cefr": "${level}"
  },
  ...
]
Focus on: varied parts of speech, real-life practical use, academic/professional contexts.`;

  const raw = await callClaude(
    "Expert English teacher. Return valid JSON arrays only. No markdown.",
    prompt,
    1800
  );
  try {
    const parsed = JSON.parse(raw.split("```json").join("").split("```").join("").trim());
    return Array.isArray(parsed) ? parsed : [];
  } catch {
    return [];
  }
}

// ── Multilingual chatbot (detects + translates) ──────────────────
export async function multilingualChat(userMessage, conversationHistory, userLevel, replyLang = "en") {
  // Detect language of input - treat empty/error result as English
  let detectedLang = "en";
  try { detectedLang = (await detectLanguage(userMessage)) || "en"; } catch {}
  const isEnglish = !detectedLang || detectedLang === "en" || detectedLang.length > 5;

  // If not English, translate to English first - fall back to original on failure
  let englishMessage = userMessage;
  if (!isEnglish) {
    try {
      const translated = await callClaude(
        "Translator. Reply ONLY with the English translation.",
        `Translate to English: "${userMessage}"`,
        150
      );
      if (translated && translated.trim()) englishMessage = translated.trim();
    } catch {}
  }

  const langLabel = LANG_LABELS[replyLang] || "English";
  const systemPrompt = `You are Alex, a friendly and expert English tutor.
The student's English level is ${userLevel}.
${!isEnglish ? `The student wrote in ${LANG_LABELS[detectedLang] || detectedLang}. Their question (translated): "${englishMessage}"` : ""}

Your response rules:
1. Always respond in English (the language being learned)
2. ${replyLang !== "en" ? `Add a ${langLabel} translation in brackets after your English response` : "Respond clearly in English"}
3. Gently correct any English mistakes with: ❌ mistake > ✅ correction
4. Be warm, encouraging, and concise (max 3 sentences)
5. If they ask a grammar question, give a clear rule + example`;

  const history = conversationHistory
    .slice(-8)
    .map(m => ({ role: m.role, content: m.content }));

  // Add the English version of the current message
  const fullHistory = [
    ...history,
    { role: "user", content: englishMessage || userMessage }
  ];

  return streamClaude(systemPrompt, fullHistory, 500);
}

