function alignWords(target, spoken) {
  const clean = (w) => w.toLowerCase().replace(/[^a-z']/g, "");
  const tArr  = target.trim().split(/\s+/);
  const sArr  = spoken.trim().split(/\s+/).filter(Boolean);
  let si = 0;
  return tArr.map((tw) => {
    if (si >= sArr.length) return { word: tw, status: "missing", said: null };
    const tc  = clean(tw);
    const sc  = clean(sArr[si]);
    if (tc === sc) { si++; return { word: tw, status: "correct", said: sArr[si - 1] }; }
    const sim = 1 - levenshtein(tc, sc) / Math.max(tc.length, sc.length, 1);
    si++;
    return { word: tw, status: sim >= 0.65 ? "close" : "wrong", said: sArr[si - 1] };
  });
}

function calcScore(aligned) {
  if (!aligned.length) return 0;
  const weights = { correct: 1, close: 0.7, wrong: 0.1, missing: 0 };
  return Math.round(
    aligned.reduce((s, x) => s + (weights[x.status] || 0), 0) / aligned.length * 100
  );
}

/* ── Waveform ───────────────────────────────────────────────── */
const Waveform = memo(function Waveform({ active, color = "var(--accent)", bars = 28, height = 36 }) {
  const heights = Array.from({ length: bars }, (_, i) =>
    Math.sin(i * 0.4) * 0.35 + Math.sin(i * 0.7) * 0.25 + 0.4
  );
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 2.5, height }}>
      {heights.map((v, i) => (
        <div key={i} style={{
          width:         3,
          borderRadius:  2,
          flexShrink:    0,
          background:    active ? color : `${color}30`,
          height:        active ? `${v * height}px` : "4px",
          animation:     active ? `wave ${0.4 + i * 0.05}s ease-in-out infinite` : "none",
          animationDelay:`${i * 0.03}s`,
          transition:    "height .3s",
        }} />
      ))}
    </div>
  );
});


