// ── Secure email OTP helpers (calls Vercel serverless functions) ──────────────
async function sendOTPToEmail(email) {
  try {
    const res = await fetch("/api/send-otp", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ email }),
    });
    const data = await res.json().catch(() => ({}));
    if (!res.ok) {
      const msg = data.error || `Failed to send OTP (${res.status})`;
      throw new Error(data.code ? `${msg} [${data.code}]` : msg);
    }
    return { ok: true };
  } catch (err) {
    return { ok: false, error: err.message };
  }
}

async function verifyOTPRemote(email, code) {
  try {
    const res = await fetch("/api/verify-otp", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ email, code }),
    });
    const data = await res.json().catch(() => ({}));
    if (!res.ok) {
      const msg = data.error || `Verification failed (${res.status})`;
      throw new Error(data.code ? `${msg} [${data.code}]` : msg);
    }
    return { ok: true, sessionToken: data.sessionToken };
  } catch (err) {
    return { ok: false, error: err.message };
  }
}

// Legacy stubs — kept so no other code breaks
function hashPass(p) {
  let h = 0;
  for (let i = 0; i < p.length; i++) h = (Math.imul(31, h) + p.charCodeAt(i)) | 0;
  return "ep_" + Math.abs(h).toString(36) + "_" + p.length;
}
function checkPass(plain, stored) { return plain === stored || hashPass(plain) === stored; }

// ── Role-based admin session ──────────────────────────────────────────────────
// Session token is written ONLY after successful backend OTP verification.
// An email match alone is NOT enough — the session token must exist.
const ADMIN_SESSION_KEY   = "ep_admin_session";
const ADMIN_SESSION_EMAIL = "ep_admin_session_email";

function grantAdminSession(email) {
  try {
    sessionStorage.setItem(ADMIN_SESSION_KEY, "1");
    sessionStorage.setItem(ADMIN_SESSION_EMAIL, email.toLowerCase().trim());
  } catch(_) {}
}
function revokeAdminSession() {
  try {
    sessionStorage.removeItem(ADMIN_SESSION_KEY);
    sessionStorage.removeItem(ADMIN_SESSION_EMAIL);
    sessionStorage.removeItem("ep_otp_session");
  } catch(_) {}
}

// SECURE: requires BOTH email in whitelist AND a live OTP session token.
// Simply signing up or logging in with an admin email is NOT enough.
function isAdminUser(user) {
  if (!user?.email) return false;
  const email = user.email.toLowerCase().trim();
  if (!ADMIN_EMAILS_LIST.includes(email)) return false;
  // Must have a session token written by grantAdminSession (set only after OTP verify)
  const sessionOk    = sessionStorage.getItem(ADMIN_SESSION_KEY) === "1";
  const sessionEmail = sessionStorage.getItem(ADMIN_SESSION_EMAIL) || "";
  return sessionOk && sessionEmail === email;
}

function checkExpiry(user) {
  if (!user?.isPro || !user?.expiryDate) return user;
  if (new Date(user.expiryDate) < new Date()) {
    const downgraded = { ...user, isPro: false, plan: "free", expiryDate: null };
    // ✅ Persist the downgrade so next load doesn't re-check a stale Pro state
    try { localStorage.setItem("ep_user", JSON.stringify(downgraded)); } catch {}
    return downgraded;
  }
  return user;
}

// ✅ Helper: true only when user is confirmed active Pro
// Admin has expiryDate:null (lifetime) - regular Pro must have a future expiry
function isActivePro(user) {
  if (!user?.isPro || user?.plan !== "pro") return false;
  // Admin account has no expiry - treat as always active
  if (user?.email?.toLowerCase().trim() === ADMIN_EMAIL) return true;
  // Regular Pro: must have a future expiry date
  if (!user?.expiryDate) return false;
  return new Date(user.expiryDate) > new Date();
}

function loadUser() {
  try { const u = localStorage.getItem("ep_user"); return u ? checkExpiry(JSON.parse(u)) : null; } catch { return null; }
}
function saveUser(u) { try { localStorage.setItem("ep_user", JSON.stringify(u)); } catch {} }

const savedUser = loadUser();
const initialState = {
  screen:      savedUser ? "home" : "login",
  user:        savedUser || { name: "Learner", level: "B1", xp: 0, streak: 7, plan: "free", email: "", isGuest: false, isNew: false, isPro: false, expiryDate: null },
  settings:    { ...DEFAULT_SETTINGS, ...(loadSettings() || {}) },
  progress:    { grammar: 42, vocabulary: 58, speaking: 30, writing: 45 },
  dailyUsage:  { pronunciation: 0, conversations: 0, aiChat: 0 },
  adminConfig: { ...(loadAdminConfig() || DEFAULT_ADMIN) },
  toasts:      [],
};

function reducer(state, action) {
  switch (action.type) {
    case "SET_SCREEN":      return { ...state, screen: action.payload };
    case "SET_USER_LEVEL":  return { ...state, user: { ...state.user, level: action.payload } };
    case "ADD_XP":          return { ...state, user: { ...state.user, xp: state.user.xp + action.payload } };
    case "UPDATE_PROGRESS": return { ...state, progress: { ...state.progress, ...action.payload } };
    case "UPDATE_SETTINGS": {
      const next = { ...state.settings, ...action.payload };
      saveSettings(next);
      return { ...state, settings: next };
    }
    case "ADD_TOAST":   return { ...state, toasts: [...state.toasts, { id: Date.now(), ...action.payload }] };
    case "REM_TOAST":   return { ...state, toasts: state.toasts.filter(t => t.id !== action.payload) };
    case "INC_USE":     return { ...state, dailyUsage: { ...state.dailyUsage, [action.key]: (state.dailyUsage[action.key] || 0) + 1 } };
    case "LOGIN": {
      // isNew=true only on fresh signup → show upgrade; login → go home
      const isNew = action.payload.isNew === true;
      // ✅ FIX #5: Resolve name priority:
      //   signup  → use the name the user typed (action.payload.name)
      //   login   → restore saved name from localStorage, or use email prefix
      const resolvedName = (action.payload.name && action.payload.name.trim())
        ? action.payload.name.trim()
        : (state.user?.name && state.user.name !== "Learner" ? state.user.name : null)
          || action.payload.email?.split("@")[0]
          || "Learner";
      const u = {
        level: "B1", xp: 0, streak: 0,
        plan: "free", isPro: false, expiryDate: null, isGuest: false,
        ...state.user,      // preserve existing stored user fields
        ...action.payload,  // override with what login/signup provides
        name: resolvedName, // ✅ guaranteed correct name
        isNew,
      };
      saveUser(u);
      return { ...state, screen: isNew ? "upgrade" : "home", user: u };
    }
    case "LOGOUT": {
      try { localStorage.removeItem("ep_settings"); localStorage.removeItem("ep_user"); } catch {}
      revokeAdminSession();
      return { ...initialState, screen:"login" };
    }
    case "UPGRADE_PRO": {
      // ✅ FIX: Pro is ONLY activated by the admin (via ADMIN_ACTIVATE).
      // This action merely records which plan the user selected and marks
      // their payment as "pending" - isPro stays FALSE until admin confirms.
      const u = {
        ...state.user,
        pendingPlan:    action.payload,          // "sixMonth" | "oneYear"
        paymentPending: true,                    // UI can show "Awaiting activation"
      };
      saveUser(u);
      // Stay on upgrade page so user sees payment instructions + WhatsApp button
      return { ...state, user: u };
    }
    case "ADMIN_ACTIVATE": {
      const VALID_PLANS = { sixMonth: 180, oneYear: 365 };
      const days = VALID_PLANS[action.plan];
      if (!days) { console.error("[ADMIN_ACTIVATE] unknown plan:", action.plan); return state; }
      const expiry = new Date(Date.now() + days * 86_400_000);
      if (expiry <= new Date()) return state; // sanity: must be in the future
      const u = {
        ...state.user,
        isPro: true, plan: "pro",
        expiryDate:     expiry.toISOString(),
        activePlan:     action.plan,
        paymentPending: false,
        pendingPlan:    null,
        activatedAt:    new Date().toISOString(),
      };
      saveUser(u);
      return { ...state, user: u };
    }
    case "DEACTIVATE_USER": {
      // ✅ FIX: update global state.user when admin deactivates
      const u = { ...state.user, isPro:false, plan:"free", expiryDate:null, paymentPending:false, pendingPlan:null };
      saveUser(u);
      return { ...state, user: u };
    }
    case "UPDATE_ADMIN": {
      const cfg = { ...state.adminConfig, ...action.payload };
      saveAdminConfig(cfg);
      return { ...state, adminConfig: cfg };
    }
    case "CHECK_EXPIRY": {
      const u = checkExpiry(state.user);
      if (u !== state.user) saveUser(u);
      return { ...state, user: u };
    }
    default: return state;
  }
}

/* ── Toast ──────────────────────────────────────────────────── */
const Toast = memo(function Toast({ toast, onRemove }) {
  useEffect(() => {
    const t = setTimeout(() => onRemove(toast.id), 3200);
    return () => clearTimeout(t);
  }, []);

  const colors = { success: "var(--green)", error: "var(--red)", info: "var(--accent)", warning: "var(--gold)" };
  const bgs    = { success: "var(--green-soft)", error: "var(--red-soft)", info: "var(--accent-soft)", warning: "var(--gold-soft)" };
  const c = colors[toast.type] || "var(--accent)";
  const bg = bgs[toast.type] || "var(--accent-soft)";

  return (
    <div style={{
      display:"flex", gap:10, alignItems:"center",
      background:"var(--surf)",
      border:`1px solid ${c}30`,
      borderLeft:`3px solid ${c}`,
      borderRadius:16,
      padding:"11px 14px",
      boxShadow:"0 8px 24px rgba(0,0,0,.12)",
      animation:"toastIn .3s ease",
      maxWidth:300, fontSize:13,
      backdropFilter:"blur(12px)",
    }}>
      <div style={{ width:28, height:28, borderRadius:12, background:bg, display:"flex", alignItems:"center", justifyContent:"center", fontSize:14, flexShrink:0 }}>
        {toast.type==="success" ? "✅" : toast.type==="error" ? "❌" : toast.type==="warning" ? "⚠️" : "ℹ️"}
      </div>
      <span style={{ flex:1, color:"var(--text)", fontWeight:500, lineHeight:1.4, fontSize:13 }}>{toast.message}</span>
      <button onClick={() => onRemove(toast.id)} style={{ background:"none", border:"none", cursor:"pointer", color:"var(--text-3)", fontSize:18, lineHeight:1, padding:2, borderRadius:6 }}>×</button>
    </div>
  );
});

/* ── Navigation ─────────────────────────────────────────────── */
/* ════════════════════════════════════════════════════════════════
   LEVEL TEST - 10 questions to identify user's CEFR level
════════════════════════════════════════════════════════════════ */
const LEVEL_QUESTIONS = [
  // A1
  { q: "Choose the correct word: I ___ a student.", options:["am","is","are","be"], answer:"am", level:"A1" },
  { q: "Which is correct?", options:["She have a cat","She has a cat","She haves a cat","She having a cat"], answer:"She has a cat", level:"A1" },
  // A2
  { q: "Choose the correct past tense: Yesterday I ___ to school.", options:["go","going","went","gone"], answer:"went", level:"A2" },
  { q: "I ___ TV when the phone rang.", options:["watched","was watching","am watching","watch"], answer:"was watching", level:"A2" },
  // B1
  { q: "She ___ in London for five years.", options:["live","lived","has lived","is living"], answer:"has lived", level:"B1" },
  { q: "If it rains tomorrow, I ___ stay home.", options:["will","would","shall","am"], answer:"will", level:"B1" },
  // B2
  { q: "The report ___ by the committee next week.", options:["will review","will be reviewed","is reviewing","reviews"], answer:"will be reviewed", level:"B2" },
  { q: "He insisted that she ___ the meeting.", options:["attends","attend","attended","attending"], answer:"attend", level:"B2" },
  // C1
  { q: "___ he studied hard, he failed the exam.", options:["Despite","Although","However","Even"], answer:"Although", level:"C1" },
  { q: "The project, ___ was completed last year, won an award.", options:["that","which","who","whose"], answer:"which", level:"C1" },
];

const LevelTest = memo(function LevelTest({ state, dispatch }) {
  const [step,      setStep]     = useState("intro"); // "intro" | "test" | "result"
  const [current,   setCurrent]  = useState(0);
  const [answers,   setAnswers]  = useState([]);
  const [selected,  setSelected] = useState(null);
  const [confirmed, setConfirmed]= useState(false);

  const q = LEVEL_QUESTIONS[current];
  const total = LEVEL_QUESTIONS.length;

  const calcLevel = (ans) => {
    // Score by level: count correct per CEFR level
    const levelScores = { A1:0, A2:0, B1:0, B2:0, C1:0 };
    const levelMax    = { A1:0, A2:0, B1:0, B2:0, C1:0 };
    LEVEL_QUESTIONS.forEach((q, i) => {
      levelMax[q.level]++;
      if (ans[i] === q.answer) levelScores[q.level]++;
    });
    // Find highest level where user got ≥50%
    const order = ["C1","B2","B1","A2","A1"];
    for (const lvl of order) {
      if (levelScores[lvl] / levelMax[lvl] >= 0.5) return lvl;
    }
    return "A1";
  };

  const handleSelect = (opt) => {
    if (confirmed) return;
    setSelected(opt);
  };

  const handleConfirm = () => {
    if (!selected) return;
    const newAnswers = [...answers, selected];
    setAnswers(newAnswers);
    setConfirmed(true);

    setTimeout(() => {
      if (current + 1 < total) {
        setCurrent(c => c + 1);
        setSelected(null);
        setConfirmed(false);
      } else {
        setStep("result");
      }
    }, 800);
  };

  const resultLevel = step === "result" ? calcLevel(answers) : null;
  const correctCount = step === "result" ? answers.filter((a, i) => a === LEVEL_QUESTIONS[i].answer).length : 0;

  const applyLevel = () => {
    dispatch({ type: "UPDATE_USER", payload: { level: resultLevel } });
    dispatch({ type: "ADD_TOAST", payload: { message: `✅ Level set to ${resultLevel}!`, type: "success" } });
    dispatch({ type: "SET_SCREEN", payload: "home" });
  };

  if (step === "intro") return (
    <div style={{ padding:24, maxWidth:520, margin:"0 auto", animation:"fadeUp .3s ease" }}>
      <div style={{ textAlign:"center", marginBottom:28 }}>
        <div style={{ fontSize:56, marginBottom:12 }}>🎯</div>
        <h2 style={{ fontFamily:"'Poppins',sans-serif", fontSize:24, fontWeight:800, color:"var(--text)", marginBottom:8 }}>
          Level Placement Test
        </h2>
        <p style={{ fontSize:14, color:"var(--text-2)", lineHeight:1.7 }}>
          10 grammar questions | Takes about 3 minutes<br/>
          We'll find your CEFR level (A1 to C1) and personalise your learning.
        </p>
        <div style={{ display:"grid", gridTemplateColumns:"repeat(5,1fr)", gap:8, margin:"20px 0" }}>
          {["A1","A2","B1","B2","C1"].map(l => (
            <div key={l} style={{ padding:"10px 0", borderRadius:12, background:LEVEL_COLORS[l]||"var(--accent)",
              color:"#fff", fontWeight:800, fontSize:13, textAlign:"center" }}>{l}</div>
          ))}
        </div>
        <div style={{ fontSize:12, color:"var(--text-3)", marginBottom:24 }}>
          Current level: <strong>{state.user.level}</strong>
        </div>
        <button className="btn-press" onClick={() => setStep("test")}
          style={{ width:"100%", padding:"14px", borderRadius:14, background:"linear-gradient(135deg,var(--accent),var(--blue))",
            border:"none", cursor:"pointer", fontSize:15, fontWeight:800, color:"#fff",
            boxShadow:"0 4px 20px rgba(108,99,255,.35)" }}>
          Start Test {'>'}
        </button>
      </div>
    </div>
  );

  if (step === "result") return (
    <div style={{ padding:24, maxWidth:520, margin:"0 auto", animation:"fadeUp .3s ease" }}>
      <div style={{ textAlign:"center", marginBottom:24 }}>
        <div style={{ fontSize:56, marginBottom:12 }}>🏆</div>
        <h2 style={{ fontFamily:"'Poppins',sans-serif", fontSize:26, fontWeight:800, color:"var(--text)", marginBottom:6 }}>
          Your Level: <span style={{ color: LEVEL_COLORS[resultLevel]||"var(--accent)" }}>{resultLevel}</span>
        </h2>
        <p style={{ fontSize:14, color:"var(--text-2)", marginBottom:20 }}>
          {correctCount}/{total} correct
        </p>
        <div style={{ padding:"16px 20px", background:"var(--surf)", border:"1px solid var(--border)",
          borderRadius:16, marginBottom:20, textAlign:"left" }}>
          {LEVEL_QUESTIONS.map((q, i) => (
            <div key={i} style={{ display:"flex", gap:10, alignItems:"center", padding:"6px 0",
              borderBottom: i < total-1 ? "1px solid var(--border)" : "none" }}>
              <span style={{ fontSize:14 }}>{answers[i] === q.answer ? "✅" : "❌"}</span>
              <div style={{ flex:1, fontSize:12, color:"var(--text-2)" }}>
                <div style={{ fontWeight:600, color:"var(--text)" }}>{q.q}</div>
                {answers[i] !== q.answer && (
                  <div style={{ color:"var(--red)", fontSize:11 }}>
                    Your answer: {answers[i]} | Correct: <strong>{q.answer}</strong>
                  </div>
                )}
              </div>
              <span style={{ fontSize:10, fontWeight:700, padding:"2px 7px", borderRadius:20,
                background:LEVEL_COLORS[q.level]+"22", color:LEVEL_COLORS[q.level]||"var(--accent)" }}>{q.level}</span>
            </div>
          ))}
        </div>
        <button className="btn-press" onClick={applyLevel}
          style={{ width:"100%", padding:"14px", borderRadius:14,
            background:`linear-gradient(135deg,${LEVEL_COLORS[resultLevel]||"var(--accent)"},var(--blue))`,
            border:"none", cursor:"pointer", fontSize:15, fontWeight:800, color:"#fff", marginBottom:10 }}>
          Set My Level to {resultLevel} v
        </button>
        <button onClick={() => { setStep("intro"); setCurrent(0); setAnswers([]); setSelected(null); setConfirmed(false); }}
          style={{ width:"100%", padding:"11px", borderRadius:16, background:"var(--surf-2)",
            border:"1.5px solid var(--border)", cursor:"pointer", fontSize:13, fontWeight:600, color:"var(--text-2)" }}>
          Retake Test
        </button>
      </div>
    </div>
  );

  // Test in progress
  const progress = Math.round((current / total) * 100);
  return (
    <div style={{ padding:24, maxWidth:520, margin:"0 auto", animation:"fadeUp .3s ease" }}>
      {/* Progress bar */}
      <div style={{ marginBottom:20 }}>
        <div style={{ display:"flex", justifyContent:"space-between", fontSize:12, color:"var(--text-3)", marginBottom:5 }}>
          <span>Question {current + 1} of {total}</span>
          <span>{q.level}</span>
        </div>
        <div style={{ height:5, background:"var(--border-2)", borderRadius:3, overflow:"hidden" }}>
          <div style={{ height:"100%", width:`${progress}%`, background:"var(--accent)", borderRadius:3, transition:"width .4s" }} />
        </div>
      </div>

      {/* Question */}
      <div style={{ background:"var(--surf)", border:"1px solid var(--border)", borderRadius:18, padding:"20px 18px", marginBottom:16 }}>
        <p style={{ fontFamily:"'Poppins',sans-serif", fontSize:17, fontWeight:700, color:"var(--text)", lineHeight:1.5, marginBottom:16 }}>
          {q.q}
        </p>
        <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
          {q.options.map(opt => {
            const isSelected = selected === opt;
            const isCorrect  = confirmed && opt === q.answer;
            const isWrong    = confirmed && isSelected && opt !== q.answer;
            return (
              <button key={opt} onClick={() => handleSelect(opt)}
                style={{
                  padding:"12px 16px", borderRadius:12, textAlign:"left", cursor: confirmed ? "default" : "pointer",
                  border:`2px solid ${isCorrect ? "var(--green)" : isWrong ? "var(--red)" : isSelected ? "var(--accent)" : "var(--border)"}`,
                  background: isCorrect ? "rgba(34,197,94,.1)" : isWrong ? "var(--red-soft)" : isSelected ? "var(--accent-soft)" : "var(--surf-2)",
                  color: isCorrect ? "var(--green)" : isWrong ? "var(--red)" : isSelected ? "var(--accent)" : "var(--text)",
                  fontSize:14, fontWeight: isSelected||isCorrect ? 700 : 500, transition:"all .15s",
                }}>
                {isCorrect ? "✅ " : isWrong ? "❌ " : ""}{opt}
              </button>
            );
          })}
        </div>
      </div>

      <button className="btn-press" onClick={handleConfirm}
        disabled={!selected || confirmed}
        style={{
          width:"100%", padding:"13px", borderRadius:14,
          background: !selected || confirmed ? "var(--surf-2)" : "linear-gradient(135deg,var(--accent),var(--blue))",
          border:"none", cursor: !selected || confirmed ? "not-allowed" : "pointer",
          fontSize:14, fontWeight:800,
          color: !selected || confirmed ? "var(--text-3)" : "#fff",
          transition:"all .2s",
        }}>
        {confirmed
          ? (current + 1 < total ? "Next Question →" : "See Results →")
          : "Confirm Answer"}
      </button>
    </div>
  );
});

