/* ════════════════════════════════════════════════════════════════
   AUTH - Validation helpers
════════════════════════════════════════════════════════════════ */
const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/;

function validateEmail(v) {
  if (!v.trim()) return "Email is required.";
  if (!emailRe.test(v.trim())) return "Enter a valid email (e.g. you@gmail.com).";
  return "";
}
function validatePassword(v) {
  if (!v) return "Password is required.";
  if (v.length < 6) return "At least 6 characters.";
  return "";
}
function validateName(v) {
  if (!v.trim()) return "Name is required.";
  if (v.trim().length < 2) return "At least 2 characters.";
  return "";
}
function validateConfirm(pass, confirm) {
  if (!confirm) return "Please confirm your password.";
  if (pass !== confirm) return "Passwords don't match.";
  return "";
}
function passwordStrength(v) {
  if (!v) return { score: 0, label: "", color: "transparent" };
  let score = 0;
  if (v.length >= 6)  score++;
  if (v.length >= 10) score++;
  if (/[A-Z]/.test(v)) score++;
  if (/[0-9]/.test(v)) score++;
  if (/[^A-Za-z0-9]/.test(v)) score++;
  const map = [
    { label: "Too short",  color: "var(--red)" },
    { label: "Weak",       color: "#F97316" },
    { label: "Fair",       color: "var(--gold)" },
    { label: "Good",       color: "#22C55E" },
    { label: "Strong",     color: "#16A34A" },
    { label: "Very strong",color: "#15803D" },
  ];
  return { score, ...map[score] };
}

/* ════════════════════════════════════════════════════════════════
   AUTH - Shared Input Field
════════════════════════════════════════════════════════════════ */
function AuthInput({ label, type = "text", value, onChange, placeholder, onKeyDown, error, touched, rightSlot, autoComplete }) {
  const hasErr = touched && error;
  return (
    <div>
      <label style={{ fontSize: 12, fontWeight: 600, color: "var(--text-2)", display: "block", marginBottom: 5 }}>
        {label}
      </label>
      <div style={{ position: "relative" }}>
        <input
          type={type}
          value={value}
          onChange={onChange}
          placeholder={placeholder}
          onKeyDown={onKeyDown}
          autoComplete={autoComplete}
          style={{
            width: "100%",
            padding: rightSlot ? "12px 44px 12px 14px" : "12px 14px",
            borderRadius: 12,
            border: `1.5px solid ${hasErr ? "var(--red)" : "var(--border)"}`,
            fontSize: 14,
            background: "var(--surf-2)",
            color: "var(--text)",
            boxSizing: "border-box",
            outline: "none",
            transition: "border-color .15s",
          }}
        />
        {rightSlot && (
          <div style={{ position: "absolute", right: 12, top: "50%", transform: "translateY(-50%)" }}>
            {rightSlot}
          </div>
        )}
      </div>
      {hasErr && (
        <div style={{ marginTop: 4, fontSize: 11, color: "var(--red)", display: "flex", alignItems: "center", gap: 4 }}>
          ⚠ {error}
        </div>
      )}
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════
   AUTH - Forgot Password Screen
════════════════════════════════════════════════════════════════ */
function ForgotPasswordScreen({ onBack }) {
  const [email,   setEmail]   = useState("");
  const [touched, setTouched] = useState(false);
  const [loading, setLoading] = useState(false);
  const [sent,    setSent]    = useState(false);

  const emailErr = validateEmail(email);
  const isAdmin  = email.trim().toLowerCase() === ADMIN_EMAIL;

  const handleReset = async () => {
    setTouched(true);
    if (emailErr) return;
    if (isAdmin) {
      // Admin password reset: redirect to WhatsApp with the recovery email
      const num = "971553156160";
      const msg = encodeURIComponent(`Hi, I need to reset the EngPath admin password. Recovery email: ${ADMIN_RECOVERY}`);
      window.open(`https://wa.me/${num}?text=${msg}`, "_blank");
      return;
    }
    setLoading(true);
    // Simulate email send - connect a real backend here
    await new Promise(r => setTimeout(r, 1100));
    setLoading(false);
    setSent(true);
  };

  return (
    <div style={{ animation: "fadeUp .25s ease" }}>
      {/* Back button */}
      <button
        onClick={onBack}
        style={{ display: "flex", alignItems: "center", gap: 6, background: "none", border: "none",
          cursor: "pointer", color: "var(--text-3)", fontSize: 13, fontWeight: 600, marginBottom: 20, padding: 0 }}
      >
        Back to Sign In
      </button>

      <div style={{ textAlign: "center", marginBottom: 22 }}>
        <div style={{ fontSize: 36, marginBottom: 8 }}>🔑</div>
        <h2 style={{ fontFamily: "'Poppins',sans-serif", fontSize: 20, fontWeight: 800, color: "var(--text)", margin: "0 0 6px" }}>
          Reset Password
        </h2>
        <p style={{ fontSize: 13, color: "var(--text-2)", lineHeight: 1.6, margin: 0 }}>
          Enter your email and we'll send you a reset link.
        </p>
      </div>

      {sent ? (
        <div style={{ textAlign: "center", padding: "20px 16px", background: "rgba(34,197,94,.08)", border: "1.5px solid rgba(34,197,94,.25)", borderRadius: 14 }}>
          <div style={{ fontSize: 32, marginBottom: 10 }}>📧</div>
          <div style={{ fontSize: 15, fontWeight: 700, color: "var(--green)", marginBottom: 6 }}>Reset link sent!</div>
          <div style={{ fontSize: 13, color: "var(--text-2)", lineHeight: 1.6 }}>
            Check your inbox at <strong>{email}</strong>.<br />
            Didn't receive it? Check spam or{" "}
            <button onClick={() => { setSent(false); setTouched(false); }}
              style={{ background: "none", border: "none", cursor: "pointer", color: "var(--accent)", fontWeight: 700, fontSize: 13, padding: 0 }}>
              try again
            </button>.
          </div>
          <button onClick={onBack}
            style={{ marginTop: 16, padding: "10px 24px", borderRadius: 12, background: "var(--accent)", border: "none", cursor: "pointer", color: "#fff", fontSize: 13, fontWeight: 700 }}>
            Back to Sign In
          </button>
        </div>
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
          <AuthInput
            label="Your Email Address"
            type="email"
            value={email}
            onChange={e => setEmail(e.target.value)}
            placeholder="you@email.com"
            onKeyDown={e => e.key === "Enter" && handleReset()}
            error={emailErr}
            touched={touched}
            autoComplete="email"
          />
          <button
            onClick={handleReset}
            disabled={loading}
            style={{
              width: "100%", padding: "13px", borderRadius: 16,
              background: "linear-gradient(135deg,var(--accent),var(--blue))",
              border: "none", cursor: loading ? "wait" : "pointer",
              fontSize: 14, fontWeight: 700, color: "#fff",
              opacity: loading ? .75 : 1,
              display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
            }}
          >
            {loading
              ? <><div style={{ width: 14, height: 14, borderRadius: "50%", border: "2px solid rgba(255,255,255,.3)", borderTopColor: "#fff", animation: "spin .7s linear infinite" }} /> Sending...</>
              : "Send Reset Link →"
            }
          </button>
        </div>
      )}
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════
   AUTH - Main LoginPage  (Login | Signup | Forgot Password)
════════════════════════════════════════════════════════════════ */
const LoginPage = memo(function LoginPage({ dispatch }) {
  /* ── Screen: "auth" | "forgot" ── */
  const [screen,   setScreen]  = useState("auth");
  /* ── Tab: "login" | "signup" ── */
  const [tab,      setTab]     = useState("login");

  /* ── Fields ── */
  const [name,     setName]    = useState("");
  const [email,    setEmail]   = useState("");
  const [pass,     setPass]    = useState("");
  const [confirm,  setConfirm] = useState("");

  /* ── UI state ── */
  const [showPass,    setShowPass]    = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const [loading,     setLoading]     = useState(false);
  const [touched,     setTouched]     = useState({});    // per-field touched flags
  const [globalError, setGlobalError] = useState("");   // server-level errors
  const [success,     setSuccess]     = useState("");   // success message

  /* Admin OTP state is declared inside handleSubmit block above */

  /* ── Per-field errors (computed, not stored) ── */
  const errs = {
    name:    tab === "signup" ? validateName(name)                : "",
    email:   validateEmail(email),
    pass:    validatePassword(pass),
    confirm: tab === "signup" ? validateConfirm(pass, confirm)   : "",
  };
  const hasAnyError = Object.values(errs).some(Boolean);

  /* ── Password strength (only shown during signup) ── */
  const strength = passwordStrength(pass);

  /* ── Reset form when switching tabs ── */
  const switchTab = (t) => {
    setTab(t);
    setTouched({});
    setGlobalError("");
    setSuccess("");
    setConfirm("");
    setShowPass(false);
    setShowConfirm(false);
  };

  /* ── Touch a field on blur ── */
  const touch = (field) => setTouched(prev => ({ ...prev, [field]: true }));

  /* ── Admin login helper ── */
  /* ── Admin OTP state ── */
  const [adminStep,      setAdminStep]      = useState("idle");  // "idle"|"email"|"otp"
  const [adminEmail,     setAdminEmail]     = useState("");
  const [otpInput,       setOtpInput]       = useState("");
  const [otpSending,     setOtpSending]     = useState(false);
  const [otpResendTimer, setOtpResendTimer] = useState(0);

  /* Resend-timer countdown */
  useEffect(() => {
    if (otpResendTimer <= 0) return;
    const t = setTimeout(() => setOtpResendTimer(s => s - 1), 1000);
    return () => clearTimeout(t);
  }, [otpResendTimer]);

  /* Admin login helper — called ONLY after backend OTP verification */
  const doAdminLogin = (verifiedEmail) => {
    grantAdminSession(verifiedEmail);
    const saved = (() => {
      try {
        const r = localStorage.getItem("ep_user");
        if (r) { const u = JSON.parse(r); if (ADMIN_EMAILS_LIST.includes(u.email?.toLowerCase())) return u; }
      } catch {} return null;
    })();
    dispatch({ type:"LOGIN", payload:{
      email: verifiedEmail.toLowerCase().trim(),
      name: "Admin", isPro: true, plan: "pro",
      xp: saved?.xp || 0, streak: saved?.streak || 0,
      expiryDate: null, isNew: false, isGuest: false,
    }});
  };

  /* Send OTP to selected admin email */
  const handleSendOTP = async (targetEmail) => {
    setOtpSending(true);
    setGlobalError("");
    const result = await sendOTPToEmail(targetEmail);
    setOtpSending(false);
    if (!result.ok) { setGlobalError(result.error || "Failed to send OTP. Try again."); return; }
    setAdminStep("otp");
    setOtpInput("");
    setOtpResendTimer(60);
  };

  /* Verify OTP via backend */
  const handleVerifyOTP = async () => {
    if (!otpInput || otpInput.length !== 6) { setGlobalError("Enter the full 6-digit code."); return; }
    setLoading(true);
    setGlobalError("");
    const result = await verifyOTPRemote(adminEmail, otpInput);
    setLoading(false);
    if (!result.ok) { setGlobalError(result.error || "Incorrect code. Try again."); return; }
    try { sessionStorage.setItem("ep_otp_session", result.sessionToken); } catch(_) {}
    doAdminLogin(adminEmail);
  };

  /* Submit */
  const handleSubmit = async () => {
    const typedEmail = email.trim().toLowerCase();
    const isAdmin    = tab === "login" && ADMIN_EMAILS_LIST.includes(typedEmail);

    // ADMIN LOGIN — redirect to OTP email-selector screen
    if (isAdmin) {
      setAdminEmail(typedEmail);
      setAdminStep("email");
      setGlobalError("");
      return;
    }

    // ── REGULAR USER FLOW ──────────────────────────────────────
    // Touch all fields at once to show every error
    setTouched({ name: true, email: true, pass: true, confirm: true });
    if (hasAnyError) return;

    setLoading(true);
    setGlobalError("");
    setSuccess("");

    try {
      // ── Replace this block with your real API call:
      // Login:  await fetch("/api/auth/login",  { method:"POST", body:JSON.stringify({ email, password:pass }) })
      // Signup: await fetch("/api/auth/signup", { method:"POST", body:JSON.stringify({ name, email, password:pass }) })
      await new Promise(r => setTimeout(r, 950));

      if (tab === "login") {
        // Restore any saved user data for this email from localStorage
        let saved = null;
        try {
          const raw = localStorage.getItem("ep_user");
          if (raw) { const u = JSON.parse(raw); if (u.email === email.trim().toLowerCase()) saved = u; }
        } catch {}

        dispatch({
          type: "LOGIN",
          payload: {
            email:   email.trim().toLowerCase(),
            name:    saved?.name || email.split("@")[0],
            isPro:   saved?.isPro   || false,
            plan:    saved?.plan    || "free",
            xp:      saved?.xp      || 0,
            streak:  saved?.streak  || 0,
            expiryDate: saved?.expiryDate || null,
            isNew:   false,
            isGuest: false,
          },
        });
      } else {
        // Signup - dispatch LOGIN with isNew:true → routes to upgrade
        dispatch({
          type: "LOGIN",
          payload: {
            email:   email.trim().toLowerCase(),
            name:    name.trim(),
            isPro:   false,
            plan:    "free",
            xp:      0,
            streak:  0,
            expiryDate: null,
            isNew:   true,
            isGuest: false,
          },
        });
      }
    } catch (e) {
      setGlobalError("Something went wrong. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  /* ── Eye toggle button ── */
  const EyeBtn = ({ show, toggle }) => (
    <button
      type="button"
      onClick={toggle}
      style={{ background: "none", border: "none", cursor: "pointer", color: "var(--text-3)", fontSize: 16, padding: 0, lineHeight: 1 }}
      tabIndex={-1}
    >
      {show ? "🙈" : "👁"}
    </button>
  );

  /* ══════════════════════════════════════════════════════
     RENDER
  ══════════════════════════════════════════════════════ */
  return (
    <div style={{
      minHeight: "100dvh", background: "var(--bg)",
      display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center",
      padding: "24px 20px", overflowY: "auto",
    }}>
      {/* ── Logo ── */}
      <div style={{ textAlign: "center", marginBottom: 28 }}>
        <div style={{
          fontFamily: "'Poppins',sans-serif", fontSize: 38, fontWeight: 900,
          background: "linear-gradient(135deg,var(--accent),var(--blue))",
          WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", marginBottom: 6,
        }}>
          EngPath
        </div>
        <div style={{ fontSize: 13, color: "var(--text-2)" }}>AI-Powered English Coach 🇬🇧</div>
      </div>

      {/* ── Card ── */}
      <div style={{
        width: "100%", maxWidth: 400,
        background: "var(--surf)", border: "1px solid var(--border)",
        borderRadius: 24, padding: "28px 24px",
        boxShadow: "0 8px 40px rgba(0,0,0,.12)",
        animation: "fadeUp .3s ease",
      }}>

        {/* ── FORGOT PASSWORD screen ── */}
        {screen === "forgot" ? (
          <ForgotPasswordScreen onBack={() => setScreen("auth")} />

        /* ── ADMIN OTP — EMAIL SELECTOR ── */
        ) : adminStep === "email" ? (
          <div style={{ display:"flex", flexDirection:"column", gap:16, animation:"fadeUp .3s ease" }}>
            <div style={{ textAlign:"center" }}>
              <div style={{ fontSize:42, marginBottom:6 }}>🔐</div>
              <div style={{ fontFamily:"'Poppins',sans-serif", fontSize:20, fontWeight:800, color:"var(--text)" }}>Admin Login</div>
              <div style={{ fontSize:12, color:"var(--text-2)", marginTop:4 }}>Select an admin email to receive your one-time code</div>
            </div>

            {globalError && (
              <div style={{ padding:"10px 14px", background:"var(--red-soft)", border:"1px solid var(--red-border)", borderRadius:12, fontSize:13, color:"var(--red)" }}>❌ {globalError}</div>
            )}

            {/* Email selector */}
            <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
              {[ADMIN_EMAIL, ADMIN_EMAIL_2].map(em => (
                <button key={em} onClick={() => setAdminEmail(em)}
                  style={{ display:"flex", alignItems:"center", gap:12, padding:"13px 16px", borderRadius:14,
                    border: adminEmail === em ? "2px solid var(--accent)" : "1.5px solid var(--border)",
                    background: adminEmail === em ? "var(--accent-soft)" : "var(--surf-2)",
                    cursor:"pointer", textAlign:"left", transition:"all .2s" }}>
                  <div style={{ width:20, height:20, borderRadius:"50%", border:"2px solid",
                    borderColor: adminEmail === em ? "var(--accent)" : "var(--border)",
                    display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>
                    {adminEmail === em && <div style={{ width:10, height:10, borderRadius:"50%", background:"var(--accent)" }}/>}
                  </div>
                  <span style={{ fontSize:13, color:"var(--text)", fontWeight: adminEmail === em ? 700 : 400 }}>{em}</span>
                </button>
              ))}
            </div>

            <button
              disabled={!adminEmail || otpSending}
              onClick={() => handleSendOTP(adminEmail)}
              style={{ width:"100%", padding:"14px", borderRadius:16,
                background: adminEmail ? "linear-gradient(135deg,var(--accent),var(--blue))" : "var(--surf-2)",
                border:"none", cursor: adminEmail ? "pointer" : "default",
                fontSize:15, fontWeight:800, color: adminEmail ? "#fff" : "var(--text-3)",
                opacity: (!adminEmail || otpSending) ? 0.65 : 1,
                boxShadow: adminEmail ? "0 4px 16px rgba(108,99,255,.35)" : "none",
                display:"flex", alignItems:"center", justifyContent:"center", gap:8 }}>
              {otpSending
                ? <><div style={{ width:14, height:14, borderRadius:"50%", border:"2px solid rgba(255,255,255,.3)", borderTopColor:"#fff", animation:"spin .7s linear infinite" }}/> Sending…</>
                : "📧 Send OTP to Email"}
            </button>

            <button onClick={() => { setAdminStep("idle"); setAdminEmail(""); setGlobalError(""); setEmail(""); }}
              style={{ background:"none", border:"none", cursor:"pointer", fontSize:12, color:"var(--text-3)", textDecoration:"underline", textAlign:"center" }}>
              Cancel
            </button>
          </div>

        /* ── ADMIN OTP — VERIFY CODE ── */
        ) : adminStep === "otp" ? (
          <div style={{ display:"flex", flexDirection:"column", gap:16, animation:"fadeUp .3s ease" }}>
            <div style={{ textAlign:"center" }}>
              <div style={{ fontSize:42, marginBottom:6 }}>📩</div>
              <div style={{ fontFamily:"'Poppins',sans-serif", fontSize:20, fontWeight:800, color:"var(--text)" }}>Check Your Email</div>
              <div style={{ fontSize:12, color:"var(--text-2)", marginTop:4 }}>
                Code sent to <strong>{adminEmail}</strong>
              </div>
            </div>

            <div style={{ background:"var(--accent-soft)", border:"1.5px solid var(--accent)", borderRadius:12, padding:"10px 16px", textAlign:"center", fontSize:12, color:"var(--accent)", fontWeight:600 }}>
              ⏱ Code expires in 10 minutes
            </div>

            {globalError && (
              <div style={{ padding:"10px 14px", background:"var(--red-soft)", border:"1px solid var(--red-border)", borderRadius:12, fontSize:13, color:"var(--red)" }}>❌ {globalError}</div>
            )}

            <input
              type="text" inputMode="numeric" maxLength={6} autoFocus
              value={otpInput}
              onChange={e => setOtpInput(e.target.value.replace(/\D/g,""))}
              placeholder="000000"
              onKeyDown={e => { if (e.key === "Enter") handleVerifyOTP(); }}
              style={{ width:"100%", padding:"16px", borderRadius:14, border:"2px solid var(--border)",
                fontSize:32, fontWeight:900, textAlign:"center", letterSpacing:"0.3em",
                background:"var(--surf-2)", color:"var(--text)", boxSizing:"border-box", outline:"none" }}
            />

            <button
              disabled={loading || otpInput.length !== 6}
              onClick={handleVerifyOTP}
              style={{ width:"100%", padding:"14px", borderRadius:16,
                background:"linear-gradient(135deg,var(--accent),var(--blue))",
                border:"none", cursor: (loading || otpInput.length !== 6) ? "default" : "pointer",
                fontSize:15, fontWeight:800, color:"#fff",
                opacity: (loading || otpInput.length !== 6) ? 0.65 : 1,
                boxShadow:"0 4px 16px rgba(108,99,255,.35)",
                display:"flex", alignItems:"center", justifyContent:"center", gap:8 }}>
              {loading
                ? <><div style={{ width:14, height:14, borderRadius:"50%", border:"2px solid rgba(255,255,255,.3)", borderTopColor:"#fff", animation:"spin .7s linear infinite" }}/> Verifying…</>
                : "✅ Verify & Sign In"}
            </button>

            <div style={{ textAlign:"center" }}>
              {otpResendTimer > 0
                ? <span style={{ fontSize:12, color:"var(--text-3)" }}>Resend available in {otpResendTimer}s</span>
                : <button onClick={() => { setOtpInput(""); handleSendOTP(adminEmail); }}
                    disabled={otpSending}
                    style={{ background:"none", border:"none", cursor:"pointer", fontSize:13, color:"var(--accent)", textDecoration:"underline", fontWeight:600 }}>
                    🔄 Resend OTP
                  </button>
              }
            </div>

            <button onClick={() => { setAdminStep("email"); setOtpInput(""); setGlobalError(""); }}
              style={{ background:"none", border:"none", cursor:"pointer", fontSize:12, color:"var(--text-3)", textDecoration:"underline", textAlign:"center" }}>
              Try a different email
            </button>
          </div>

        ) : (
          <>
            {/* ── Tab switcher ── */}
            <div style={{ display: "flex", background: "var(--surf-2)", borderRadius: 16, padding: 4, marginBottom: 24, gap: 4 }}>
              {[["login","Sign In"],["signup","Create Account"]].map(([t, label]) => (
                <button key={t} onClick={() => switchTab(t)} style={{
                  flex: 1, padding: "10px 8px", borderRadius: 12, border: "none",
                  cursor: "pointer", fontSize: 13, fontWeight: 700, transition: "all .2s",
                  background: tab === t ? "var(--surf)" : "transparent",
                  color:      tab === t ? "var(--text)" : "var(--text-3)",
                  boxShadow:  tab === t ? "0 1px 8px rgba(0,0,0,.1)" : "none",
                }}>
                  {label}
                </button>
              ))}
            </div>

            {/* ── Success banner ── */}
            {success && (
              <div style={{ marginBottom: 14, padding: "10px 14px", background: "rgba(34,197,94,.1)", border: "1px solid rgba(34,197,94,.3)", borderRadius: 12, fontSize: 13, color: "var(--green)", display: "flex", gap: 8, alignItems: "center" }}>
                ✅ {success}
              </div>
            )}

            {/* ── Global error banner ── */}
            {globalError && (
              <div style={{ marginBottom: 14, padding: "10px 14px", background: "var(--red-soft)", border: "1px solid var(--red-border)", borderRadius: 12, fontSize: 13, color: "var(--red)", display: "flex", gap: 8, alignItems: "center" }}>
                ❌ {globalError}
              </div>
            )}

            <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>

              {/* Name (signup only) */}
              {tab === "signup" && (
                <AuthInput
                  label="Your Name"
                  type="text"
                  value={name}
                  onChange={e => setName(e.target.value)}
                  placeholder="e.g. Alex"
                  error={errs.name}
                  touched={touched.name}
                  autoComplete="name"
                  onKeyDown={e => e.key === "Enter" && handleSubmit()}
                />
              )}

              {/* Email */}
              <AuthInput
                label="Email Address"
                type="email"
                value={email}
                onChange={e => { setEmail(e.target.value); }}
                placeholder="you@email.com"
                error={errs.email}
                touched={touched.email}
                autoComplete="email"
                onKeyDown={e => e.key === "Enter" && handleSubmit()}
              />

              {/* Password field — hidden for admin emails (OTP flow takes over on submit) */}
              {tab === "login" && ADMIN_EMAILS_LIST.includes(email.trim().toLowerCase()) ? (
                <div style={{ padding:"11px 14px", background:"var(--gold-soft)", border:"1px solid var(--gold-border)", borderRadius:12, fontSize:13, fontWeight:700, color:"var(--gold)", display:"flex", gap:8, alignItems:"center" }}>
                  🔐 Admin Account — OTP will be sent to your email
                </div>
              ) : (
              <div>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 5 }}>
                  <label style={{ fontSize: 12, fontWeight: 600, color: "var(--text-2)" }}>Password</label>
                  {tab === "login" && (
                    <button
                      type="button"
                      onClick={() => setScreen("forgot")}
                      style={{ background: "none", border: "none", cursor: "pointer", fontSize: 11, color: "var(--accent)", fontWeight: 700, padding: 0 }}
                    >
                      Forgot password?
                    </button>
                  )}
                </div>
                <div style={{ position: "relative" }}>
                  <input
                    type={showPass ? "text" : "password"}
                    value={pass}
                    onChange={e => setPass(e.target.value)}
                    onBlur={() => touch("pass")}
                    placeholder="Min. 6 characters"
                    onKeyDown={e => e.key === "Enter" && handleSubmit()}
                    autoComplete={tab === "login" ? "current-password" : "new-password"}
                    style={{
                      width: "100%", padding: "12px 44px 12px 14px",
                      borderRadius: 12, boxSizing: "border-box",
                      border: `1.5px solid ${touched.pass && errs.pass ? "var(--red)" : "var(--border)"}`,
                      fontSize: 14, background: "var(--surf-2)", color: "var(--text)", outline: "none",
                    }}
                  />
                  <button type="button" onClick={() => setShowPass(s => !s)} tabIndex={-1}
                    style={{ position: "absolute", right: 12, top: "50%", transform: "translateY(-50%)", background: "none", border: "none", cursor: "pointer", color: "var(--text-3)", fontSize: 16, padding: 0, lineHeight: 1 }}>
                    {showPass ? "🙈" : "👁"}
                  </button>
                </div>
                {/* Field error */}
                {touched.pass && errs.pass && (
                  <div style={{ marginTop: 4, fontSize: 11, color: "var(--red)" }}>⚠ {errs.pass}</div>
                )}
                {/* Password strength meter (signup only) */}
                {tab === "signup" && pass.length > 0 && (
                  <div style={{ marginTop: 7 }}>
                    <div style={{ display: "flex", gap: 3, marginBottom: 3 }}>
                      {[1,2,3,4,5].map(i => (
                        <div key={i} style={{
                          flex: 1, height: 3, borderRadius: 2,
                          background: i <= strength.score ? strength.color : "var(--border-2)",
                          transition: "background .25s",
                        }} />
                      ))}
                    </div>
                    <div style={{ fontSize: 10, color: strength.color, fontWeight: 600 }}>
                      {strength.label}
                    </div>
                  </div>
                )}
              </div>
              )} {/* end password conditional */}

              {/* Confirm password (signup only) */}
              {tab === "signup" && (
                <div>
                  <label style={{ fontSize: 12, fontWeight: 600, color: "var(--text-2)", display: "block", marginBottom: 5 }}>
                    Confirm Password
                  </label>
                  <div style={{ position: "relative" }}>
                    <input
                      type={showConfirm ? "text" : "password"}
                      value={confirm}
                      onChange={e => setConfirm(e.target.value)}
                      onBlur={() => touch("confirm")}
                      placeholder="Re-enter your password"
                      onKeyDown={e => e.key === "Enter" && handleSubmit()}
                      autoComplete="new-password"
                      style={{
                        width: "100%", padding: "12px 44px 12px 14px",
                        borderRadius: 12, boxSizing: "border-box",
                        border: `1.5px solid ${touched.confirm && errs.confirm ? "var(--red)" : pass && confirm && pass === confirm ? "var(--green)" : "var(--border)"}`,
                        fontSize: 14, background: "var(--surf-2)", color: "var(--text)", outline: "none",
                      }}
                    />
                    <button type="button" onClick={() => setShowConfirm(s => !s)} tabIndex={-1}
                      style={{ position: "absolute", right: 12, top: "50%", transform: "translateY(-50%)", background: "none", border: "none", cursor: "pointer", color: "var(--text-3)", fontSize: 16, padding: 0, lineHeight: 1 }}>
                      {showConfirm ? "🙈" : "👁"}
                    </button>
                    {/* Match checkmark */}
                    {pass && confirm && pass === confirm && (
                      <div style={{ position: "absolute", right: 40, top: "50%", transform: "translateY(-50%)", color: "var(--green)", fontSize: 14 }}>v</div>
                    )}
                  </div>
                  {touched.confirm && errs.confirm && (
                    <div style={{ marginTop: 4, fontSize: 11, color: "var(--red)" }}>⚠ {errs.confirm}</div>
                  )}
                </div>
              )}

              {/* Submit button */}
              <button
                className="btn-press"
                onClick={handleSubmit}
                disabled={loading}
                style={{
                  width: "100%", padding: "14px", borderRadius: 16, marginTop: 2,
                  background: "linear-gradient(135deg,var(--accent),var(--blue))",
                  border: "none", cursor: loading ? "wait" : "pointer",
                  fontSize: 14, fontWeight: 800, color: "#fff",
                  opacity: loading ? .75 : 1,
                  display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
                  boxShadow: "0 4px 16px rgba(108,99,255,.35)",
                  transition: "opacity .15s, transform .1s",
                }}
              >
                {loading
                  ? <><div style={{ width: 14, height: 14, borderRadius: "50%", border: "2px solid rgba(255,255,255,.3)", borderTopColor: "#fff", animation: "spin .7s linear infinite" }} /> Processing...</>
                  : (tab === "login" && ADMIN_EMAILS_LIST.includes(email.trim().toLowerCase())) ? "📧 Continue with OTP →" : tab === "login" ? "Sign In →" : "Create Account →"
                }
              </button>

            </div>

            {/* Divider */}
            <div style={{ position: "relative", margin: "20px 0", textAlign: "center" }}>
              <div style={{ height: 1, background: "var(--border)", position: "absolute", top: "50%", left: 0, right: 0 }} />
              <span style={{ position: "relative", background: "var(--surf)", padding: "0 12px", fontSize: 11, color: "var(--text-3)", fontWeight: 600 }}>or</span>
            </div>

            {/* Guest */}
            <button
              className="btn-press"
              onClick={() => dispatch({ type: "LOGIN", payload: { name: "Guest", isGuest: true, isPro: false, plan: "free", xp: 0, streak: 0, isNew: false } })}
              style={{
                width: "100%", padding: "12px", borderRadius: 16,
                background: "var(--surf-2)", border: "1.5px solid var(--border)",
                cursor: "pointer", fontSize: 13, fontWeight: 600, color: "var(--text-2)",
                display: "flex", alignItems: "center", justifyContent: "center", gap: 6,
              }}
            >
              👤 Continue as Guest
            </button>

            <p style={{ textAlign: "center", fontSize: 11, color: "var(--text-3)", marginTop: 16, lineHeight: 1.7 }}>
              🔒 Secure | No spam | Cancel anytime
            </p>
            <div style={{ textAlign:"center", marginTop:10, paddingTop:10, borderTop:"1px solid var(--border)" }}>
              <span style={{ fontSize:10, color:"var(--text-3)", fontFamily:"'Inter',sans-serif", letterSpacing:".02em" }}>
                Powered by{" "}
                <strong style={{ color:"var(--accent)", fontWeight:700 }}>Zoraak Technologies</strong>
              </span>
            </div>
          </>
        )}
      </div>
    </div>
  );
});


const UpgradePage = memo(function UpgradePage({ dispatch, state }) {
  const [billing,   setBilling]   = useState("yearly");
  const [currency,  setCurrency]  = useState({ code:"AED", country:"" });
  const [planSel,   setPlanSel]   = useState("oneYear");
  const [step,      setStep]      = useState("plans"); // "plans" | "payment"
  const adminCfg  = state?.adminConfig || {};
  const userEmail = state?.user?.email || "";
  const isPending = state?.user?.paymentPending === true;
  const plans = adminCfg.plans || { sixMonth:{price:49,label:"6 Months",days:180,bestValue:false}, oneYear:{price:79,label:"1 Year",days:365,bestValue:true} };

  useEffect(() => {
    detectCurrency().then(c => setCurrency(c));
    // urgency timer handled by display
  }, []);

  const getPrice = (aedPrice) => {
    const local = convertPrice(aedPrice, currency.code);
    return currency.code === "AED" ? `AED ${aedPrice}` : `${currency.code} ${local}`;
  };

  const FEATURES = [
    { icon:"🎙", label:"Unlimited Speaking Practice",   free:"5/day",       pro:"Unlimited" },
    { icon:"🤖", label:"Advanced AI Feedback",           free:"10 msg/day",  pro:"Unlimited" },
    { icon:"📚", label:"Full Vocabulary (1500+ words)",  free:"Seed words",  pro:"All + AI Gen" },
    { icon:"💬", label:"Conversation Scenarios",         free:"3/day",       pro:"Unlimited" },
    { icon:"🔍", label:"Smart Dictionary",               free:"Basic",       pro:"Full + History" },
    { icon:"📖", label:"All Grammar Lessons",            free:"Static only", pro:"AI-powered" },
    { icon:"🌐", label:"Translation Languages",       free:"5 languages",  pro:`All ${10}` },
    { icon:"📊", label:"Progress Analytics",             free:"Basic",       pro:"Detailed" },
  ];

// plans come from adminCfg above

  return (
    <div style={{ minHeight:"100dvh", background:"var(--bg)", overflowY:"auto" }}>
      <div style={{ maxWidth:420, margin:"0 auto", padding:"24px 20px 40px" }}>

        {/* Header */}
        <div style={{ textAlign:"center", marginBottom:24 }}>
          <div style={{ fontSize:32, marginBottom:8 }}>⭐</div>
          <div style={{ fontFamily:"'Poppins',sans-serif", fontSize:26, fontWeight:700, color:"var(--text)", marginBottom:6 }}>Upgrade to Pro</div>
          <div style={{ fontSize:14, color:"var(--text-2)", lineHeight:1.6 }}>Speak like a native. Learn without limits.</div>
        </div>

        {/* ── STEP 1: Plan selector ── */}
        {step === "plans" && (<>

        {/* Urgency badge */}
        <div style={{ background:"linear-gradient(135deg,#F59E0B,#EF4444)", borderRadius:12, padding:"10px 16px", textAlign:"center", marginBottom:20, boxShadow:"0 4px 20px rgba(245,158,11,.3)" }}>
          <div style={{ fontSize:13, fontWeight:700, color:"#fff" }}>🔥 Limited Time - 40% OFF Yearly Plan</div>
          <div style={{ fontSize:11, color:"rgba(255,255,255,.85)", marginTop:2 }}>Offer expires when the timer runs out</div>
        </div>

        {/* Billing toggle */}
        <div style={{ display:"flex", background:"var(--surf-2)", borderRadius:12, padding:4, marginBottom:20 }}>
          {["monthly","yearly"].map(b=>(
            <button key={b} onClick={()=>setBilling(b)}
              style={{ flex:1, padding:"9px", borderRadius:12, border:"none", cursor:"pointer", fontSize:12, fontWeight:700, transition:"all .2s", position:"relative",
                background: billing===b ? "var(--surf)" : "transparent",
                color: billing===b ? "var(--text)" : "var(--text-3)",
                boxShadow: billing===b ? "0 1px 6px rgba(0,0,0,.1)" : "none",
              }}>
              {b==="monthly" ? "Monthly" : <>Yearly <span style={{fontSize:10,background:"#22C55E",color:"#fff",padding:"1px 6px",borderRadius:20,marginLeft:4}}>-40%</span></>}
            </button>
          ))}
        </div>

        {/* Plan selector cards */}
        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10, marginBottom:16 }}>
          {Object.entries(plans).map(([key,p])=>{
            const sel = planSel===key;
            const localPrice = getPrice(p.price);
            const otherPrice = p.price === plans.sixMonth?.price ? plans.oneYear?.price : plans.sixMonth?.price;
            const savings = otherPrice ? Math.round((1-p.price/(otherPrice*2))*100) : 0;
            return (
              <div key={key} onClick={()=>setPlanSel(key)}
                style={{ padding:"14px 12px", borderRadius:16, cursor:"pointer", textAlign:"center", transition:"all .2s",
                  background: sel ? "linear-gradient(135deg,var(--accent),var(--blue))" : "var(--surf)",
                  border: sel ? "none" : "2px solid var(--border)",
                  boxShadow: sel ? "0 6px 24px rgba(108,99,255,.35)" : "var(--shadow)",
                  position:"relative" }}>
                {p.bestValue && <div style={{position:"absolute",top:-8,left:"50%",transform:"translateX(-50%)",background:"#F59E0B",color:"#fff",fontSize:9,fontWeight:800,padding:"2px 8px",borderRadius:20,letterSpacing:".05em",whiteSpace:"nowrap"}}>BEST VALUE</div>}
                <div style={{ fontFamily:"'Poppins',sans-serif", fontSize:22, fontWeight:800, color:sel?"#fff":"var(--text)", marginBottom:2 }}>{localPrice}</div>
                {currency.code!=="AED" && <div style={{fontSize:9,color:sel?"rgba(255,255,255,.7)":"var(--text-3)",marginBottom:4}}>~ AED {p.price} | Charged in AED</div>}
                <div style={{ fontSize:11, color:sel?"rgba(255,255,255,.85)":"var(--text-2)", marginBottom:4 }}>{p.label}</div>
                {key==="oneYear" && savings>0 && <div style={{fontSize:10,fontWeight:700,color:sel?"#4ade80":"var(--green)"}}>Save ~{savings}%</div>}
              </div>
            );
          })}
        </div>

        {/* ✅ FIX: CTA goes to payment step - does NOT activate Pro */}
        <div style={{ background:"linear-gradient(135deg,var(--accent),var(--blue))", borderRadius:20, padding:"20px", marginBottom:16, boxShadow:"0 8px 32px rgba(108,99,255,.35)" }}>
          <div style={{ fontSize:12, color:"rgba(255,255,255,.8)", marginBottom:8 }}>
            ⏱ Pro activated within 1 hour after admin confirms payment
          </div>
          <button className="btn-press"
            onClick={() => {
              // ✅ Record selected plan as PENDING - isPro stays false
              dispatch({ type:"UPGRADE_PRO", payload:planSel });
              setStep("payment");
            }}
            style={{ width:"100%", padding:"14px", borderRadius:14, background:"#fff", border:"none", cursor:"pointer", fontSize:15, fontWeight:800, color:"var(--accent)", boxShadow:"0 4px 16px rgba(0,0,0,.2)", marginBottom:8 }}>
            Choose {plans[planSel]?.label || "Plan"} - See Payment Details {'>'}
          </button>
          <div style={{ textAlign:"center", fontSize:11, color:"rgba(255,255,255,.7)" }}>Pay then WhatsApp screenshot, Admin activates</div>
        </div>

        {/* Features comparison */}
        <div style={{ background:"var(--surf)", border:"1px solid var(--border)", borderRadius:18, overflow:"hidden", marginBottom:16 }}>
          <div style={{ display:"grid", gridTemplateColumns:"1fr 80px 80px", padding:"10px 14px", background:"var(--surf-2)", borderBottom:"1px solid var(--border)" }}>
            <div style={{ fontSize:11, fontWeight:700, color:"var(--text-2)" }}>Feature</div>
            <div style={{ textAlign:"center", fontSize:11, fontWeight:700, color:"var(--text-3)" }}>Free</div>
            <div style={{ textAlign:"center", fontSize:11, fontWeight:800, color:"var(--accent)" }}>Pro ⭐</div>
          </div>
          {FEATURES.map(f=>(
            <div key={f.label} style={{ display:"grid", gridTemplateColumns:"1fr 80px 80px", padding:"11px 14px", borderBottom:"1px solid var(--border)" }}>
              <div style={{ fontSize:12, color:"var(--text-2)", display:"flex", gap:6, alignItems:"center" }}><span>{f.icon}</span>{f.label}</div>
              <div style={{ textAlign:"center", fontSize:10, color:"var(--text-3)" }}>{f.free}</div>
              <div style={{ textAlign:"center", fontSize:10, fontWeight:700, color:"var(--green)" }}>{f.pro}</div>
            </div>
          ))}
        </div>

        {/* Skip */}
        <div style={{ textAlign:"center" }}>
          <button onClick={()=>dispatch({type:"SET_SCREEN",payload:"home"})}
            style={{ background:"none", border:"none", cursor:"pointer", fontSize:11, color:"var(--text-3)", textDecoration:"underline" }}>
            Skip for now (free plan)
          </button>
        </div>
        </>)}

        {/* ── STEP 2: Payment instructions ── */}
        {step === "payment" && (<>
          <button onClick={()=>setStep("plans")}
            style={{ display:"flex", alignItems:"center", gap:6, background:"none", border:"none", cursor:"pointer", color:"var(--text-3)", fontSize:13, fontWeight:600, marginBottom:20, padding:0 }}>
            Back to Plans
          </button>

          {/* Pending notice */}
          <div style={{ background:"var(--gold-soft)", border:"1px solid var(--gold-border)", borderRadius:16, padding:"14px 16px", marginBottom:16 }}>
            <div style={{ fontSize:13, fontWeight:700, color:"var(--gold)", marginBottom:4 }}>
              ⏳ Payment Pending - Account not yet activated
            </div>
            <div style={{ fontSize:12, color:"var(--text-2)", lineHeight:1.6 }}>
              Your plan: <strong>{plans[planSel]?.label}</strong> | {getPrice(plans[planSel]?.price)}<br/>
              <span style={{ fontSize:11, color:"var(--text-3)" }}>
                Pro access is activated manually by the admin after payment is confirmed.
              </span>
            </div>
          </div>

          {/* Payment details */}
          <div style={{ background:"var(--surf)", border:"1px solid var(--border)", borderRadius:16, padding:"16px", marginBottom:14 }}>
            <div style={{ fontSize:13, fontWeight:700, color:"var(--text)", marginBottom:10 }}>💳 Payment Details</div>
            {(adminCfg.showBankTransfer ?? true) && adminCfg.bankName && (
              <div style={{ display:"grid", gridTemplateColumns:"auto 1fr", gap:"6px 12px", fontSize:12, color:"var(--text-2)", lineHeight:1.8 }}>
                <span style={{ fontWeight:600, color:"var(--text-3)" }}>Bank</span>
                <span>{adminCfg.bankName}</span>
                {adminCfg.bankHolder && <><span style={{ fontWeight:600, color:"var(--text-3)" }}>Account</span><span>{adminCfg.bankHolder}</span></>}
                {adminCfg.bankIBAN && <><span style={{ fontWeight:600, color:"var(--text-3)" }}>IBAN</span><span style={{ fontFamily:"monospace", fontSize:11 }}>{adminCfg.bankIBAN}</span></>}
                <span style={{ fontWeight:600, color:"var(--text-3)" }}>Amount</span>
                <span style={{ fontWeight:700, color:"var(--text)" }}>{getPrice(plans[planSel]?.price)}</span>
              </div>
            )}
            {adminCfg.paymentNote && (
              <div style={{ marginTop:10, padding:"8px 11px", background:"var(--accent-soft)", borderRadius:12, fontSize:12, color:"var(--accent)", lineHeight:1.6 }}>
                💡 {adminCfg.paymentNote}
              </div>
            )}
          </div>

          {/* ── UPI / GPay / PhonePe ── */}
          {(adminCfg.showUPI ?? false) && adminCfg.upiId && (
            <div style={{ background:"var(--surf)", border:"1px solid var(--border)", borderRadius:18, padding:"16px", marginBottom:12, boxShadow:"var(--shadow-sm)" }}>
              <div style={{ fontFamily:"'Poppins',sans-serif", fontSize:13, fontWeight:700, color:"var(--text)", marginBottom:12 }}>📱 UPI / GPay / PhonePe</div>
              <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"10px 0", borderBottom:"1px solid var(--border)" }}>
                <div>
                  <div style={{ fontSize:10, fontWeight:700, color:"var(--text-3)", textTransform:"uppercase", letterSpacing:".05em" }}>UPI ID</div>
                  <div style={{ fontSize:16, fontWeight:900, color:"var(--text)", marginTop:2, fontFamily:"monospace" }}>{adminCfg.upiId}</div>
                  {adminCfg.upiName && <div style={{ fontSize:11, color:"var(--text-3)", marginTop:2 }}>{adminCfg.upiName}</div>}
                </div>
                <button onClick={()=>{ try{ navigator.clipboard.writeText(adminCfg.upiId); }catch(_){} dispatch({type:"ADD_TOAST",payload:{message:"✅ UPI ID copied!",type:"success"}}); }}
                  style={{ padding:"9px 18px", borderRadius:20, background:"var(--accent-soft)", border:"1.5px solid var(--accent-border)", cursor:"pointer", fontSize:12, fontWeight:700, color:"var(--accent)" }}>
                  📋 Copy
                </button>
              </div>
              <div style={{ marginTop:10, fontSize:11, color:"var(--text-3)", padding:"8px 10px", background:"var(--surf-2)", borderRadius:10, lineHeight:1.7 }}>
                📲 Open <strong>GPay / PhonePe / Paytm</strong> → Send Money → Paste UPI ID → Pay <strong>{getPrice(plans[planSel]?.price)}</strong>
              </div>
            </div>
          )}

          {/* ── WhatsApp with toggle ── */}
          {(adminCfg.showWhatsApp ?? true) && (
          <WhatsAppButton adminConfig={adminCfg} userEmail={userEmail} pendingPlan={planSel} style={{ marginBottom:14, borderRadius:14 }}/>
          )}

          {/* Steps */}
          <div style={{ background:"var(--surf)", border:"1px solid var(--border)", borderRadius:14, padding:"14px 16px", marginBottom:16 }}>
            <div style={{ fontSize:12, fontWeight:700, color:"var(--text)", marginBottom:10 }}>📋 Activation Steps</div>
            {["Make bank transfer using the details above",
              "Screenshot your payment confirmation",
              "Tap 'Contact on WhatsApp' above and send the screenshot",
              "Include your email: " + (userEmail || "your registered email"),
              "Admin activates your Pro account within 1 hour"].map((s,i)=>(
              <div key={i} style={{ display:"flex", gap:10, marginBottom:8, alignItems:"flex-start" }}>
                <span style={{ width:20, height:20, borderRadius:"50%", background:"var(--accent)", color:"#fff", fontSize:10, fontWeight:800, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0, marginTop:1 }}>{i+1}</span>
                <span style={{ fontSize:12, color:"var(--text-2)", lineHeight:1.6 }}>{s}</span>
              </div>
            ))}
          </div>

          <button onClick={()=>dispatch({type:"SET_SCREEN",payload:"home"})}
            style={{ width:"100%", padding:"12px", borderRadius:16, background:"var(--surf-2)", border:"1.5px solid var(--border)", cursor:"pointer", fontSize:13, fontWeight:600, color:"var(--text-2)" }}>
            Done - I'll wait for activation
          </button>
        </>)}
      </div>
    </div>
  );
});

