function FaqItem({ q, a }) {
  const [open, setOpen] = useState(false);
  return (
    <div style={{ background:"var(--surf)", border:"1px solid var(--border)", borderRadius:14, marginBottom:8, overflow:"hidden" }}>
      <div onClick={()=>setOpen(o=>!o)} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"14px 16px", cursor:"pointer" }}>
        <span style={{ fontSize:14, fontWeight:600, color:"var(--text)", flex:1, paddingRight:10 }}>{q}</span>
        <span style={{ color:"var(--accent)", fontSize:18, transition:"transform .2s", transform:open?"rotate(45deg)":"none", flexShrink:0 }}>+</span>
      </div>
      {open && <div style={{ padding:"0 16px 14px", fontSize:13, color:"var(--text-2)", lineHeight:1.7, borderTop:"1px solid var(--border)", paddingTop:12 }}>{a}</div>}
    </div>
  );
}

const FaqPage = memo(function FaqPage({ dispatch, state }) {
  const adminCfg  = state?.adminConfig || {};
  const userEmail = state?.user?.email || "";
  const faqs = [
    { q:"How do I activate Pro?", a:"After payment, tap 'Contact on WhatsApp' on the Upgrade page and send your payment screenshot. The admin will activate your account within 1 hour." },
    { q:"How long does activation take?", a:"Usually within 1 hour during working hours (9am–10pm UAE time). You will receive a WhatsApp confirmation." },
    { q:"What languages are supported for translation?", a:"Malayalam, Hindi, Tamil, Telugu, Arabic, French, German, Spanish, Chinese, Japanese, and Korean. You can change the translation language in Settings." },
    { q:"What payment methods are accepted?", a:"Bank transfer and QR code payment. Details are shown on the Upgrade page. You can also contact us on WhatsApp for other payment options." },
    { q:"Can I speak Malayalam to the AI coach?", a:"Yes! In the Chatbot, tap the 🌐 button to speak in Malayalam, Hindi, Arabic or any language. The AI understands and responds in English." },
    { q:"What is the difference between Free and Pro?", a:"Free plan has daily limits (5 speaking, 3 conversations, 10 AI messages). Pro gives you unlimited access to all features including full vocabulary and advanced AI feedback." },
    { q:"How do I practice pronunciation?", a:"Go to Speaking → listen to the sentence → press the mic and speak → AI scores your accuracy with colour-coded word feedback." },
    { q:"What happens when my Pro plan expires?", a:"Your account automatically reverts to the Free plan. You can renew any time by contacting us on WhatsApp." },
    { q:"Is my data private?", a:"Yes. Your account data is stored locally on your device. AI conversations are not stored permanently." },
    { q:"I paid but my account is not activated yet.", a:`Contact us on WhatsApp: wa.me/${adminCfg.whatsapp||"971501234567"} with your payment screenshot.` },
  ];
  return (
    <div style={{ padding:"16px", maxWidth:680, margin:"0 auto", animation:"fadeUp .3s ease" }}>
      <button onClick={()=>dispatch({type:"SET_SCREEN",payload:"home"})}
        style={{ background:"none", border:"none", cursor:"pointer", fontSize:22, color:"var(--text-2)", marginBottom:12 }}><svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><polyline points="15,18 9,12 15,6"/></svg></button>
      <h2 style={{ fontFamily:"'Poppins',sans-serif", fontSize:22, fontWeight:700, color:"var(--text)", marginBottom:4 }}>FAQ</h2>
      <p style={{ fontSize:13, color:"var(--text-2)", marginBottom:20 }}>Frequently asked questions</p>
      {faqs.map((f,i)=><FaqItem key={i} q={f.q} a={f.a}/>)}
      <div style={{ marginTop:20 }}>
        <WhatsAppButton adminConfig={adminCfg} userEmail={userEmail}/>
      </div>
    </div>
  );
});

/* ════════════════════════════════════════════════════════════════
   ADMIN PANEL
════════════════════════════════════════════════════════════════ */
const AdminPanel = memo(function AdminPanel({ state, dispatch }) {
  const [tab,        setTab]       = useState("dashboard");
  const [searchEmail,setSearch]    = useState("");
  const [userFound,  setUserFound] = useState(null);   // null | "not_found" | userObj
  const [planSel,    setPlanSel]   = useState("oneYear");
  const [saved,      setSaved]     = useState(false);
  const [actLog,     setActLog]    = useState(() => {
    try { return JSON.parse(localStorage.getItem("ep_admin_log")||"[]"); } catch { return []; }
  });

  // Security tab
  const [secOldPass,  setSecOldPass]  = useState("");
  const [secNewPass,  setSecNewPass]  = useState("");
  const [secConfPass, setSecConfPass] = useState("");
  const [secRecEmail, setSecRecEmail] = useState(loadAdminCreds().recoveryEmail || ADMIN_RECOVERY);
  const [secMsg,      setSecMsg]      = useState({ type:"", text:"" });
  const [twoFAEnabled,setTwoFA]       = useState(loadAdminCreds().twoFA !== false);

  const cfg = state.adminConfig || {};

  // ── Helpers ──────────────────────────────────────────────────
  const toast = (msg, type="success") => dispatch({ type:"ADD_TOAST", payload:{ message:msg, type } });

  const addLog = (action, detail) => {
    const entry = { action, detail, time: new Date().toLocaleString() };
    const log = [entry, ...actLog].slice(0, 50);
    setActLog(log);
    try { localStorage.setItem("ep_admin_log", JSON.stringify(log)); } catch {}
  };

  const showSecMsg = (type, text) => {
    setSecMsg({ type, text });
    setTimeout(() => setSecMsg({ type:"", text:"" }), 3000);
  };

  const updateCfg = (key, val) => {
    dispatch({ type:"UPDATE_ADMIN", payload:{ [key]:val } });
    setSaved(true); setTimeout(() => setSaved(false), 2000);
  };

  const updatePlan = (planKey, field, val) => {
    const plans = { ...cfg.plans, [planKey]:{ ...cfg.plans[planKey], [field]:val } };
    dispatch({ type:"UPDATE_ADMIN", payload:{ plans } });
    setSaved(true); setTimeout(() => setSaved(false), 2000);
  };

  // ── Find user ─────────────────────────────────────────────────
  const findUser = () => {
    if (!searchEmail.trim()) return;
    try {
      const raw = localStorage.getItem("ep_user");
      if (raw) {
        const u = JSON.parse(raw);
        if (u.email?.toLowerCase().trim() === searchEmail.toLowerCase().trim()) {
          setUserFound(u);
        } else {
          setUserFound("not_found");
        }
      } else {
        setUserFound("not_found");
      }
    } catch { setUserFound("not_found"); }
  };

  // ── Activate Pro ──────────────────────────────────────────────
  const activateUser = (planKey) => {
    if (!userFound || userFound === "not_found") return;
    const days   = planKey === "sixMonth" ? 180 : 365;
    const expiry = new Date(Date.now() + days * 86400000).toISOString();
    const updated = { ...userFound, isPro:true, plan:"pro", expiryDate:expiry, activePlan:planKey, paymentPending:false, pendingPlan:null, activatedAt:new Date().toISOString() };
    try { localStorage.setItem("ep_user", JSON.stringify(updated)); } catch {}
    dispatch({ type:"ADMIN_ACTIVATE", plan:planKey });
    setUserFound(updated);
    addLog("✅ Activated Pro", `${userFound.email} · ${planKey === "sixMonth" ? "6 Months" : "1 Year"} · expires ${new Date(expiry).toLocaleDateString()}`);
    toast(`✅ Pro activated for ${userFound.email}!`);
  };

  // ── Deactivate ────────────────────────────────────────────────
  const deactivateUser = () => {
    if (!userFound || userFound === "not_found") return;
    const updated = { ...userFound, isPro:false, plan:"free", expiryDate:null, paymentPending:false, pendingPlan:null };
    try { localStorage.setItem("ep_user", JSON.stringify(updated)); } catch {}
    dispatch({ type:"DEACTIVATE_USER" });
    setUserFound(updated);
    addLog("🚫 Deactivated", userFound.email);
    toast(`Pro removed for ${userFound.email}`, "error");
  };

  // ── Save security ─────────────────────────────────────────────
  const saveSecurity = () => {
    if (secNewPass && secNewPass !== secConfPass) { showSecMsg("error","Passwords don't match"); return; }
    if (secNewPass && secNewPass.length < 6) { showSecMsg("error","Min 6 characters"); return; }
    const creds = loadAdminCreds();
    const updated = { ...creds, twoFA: twoFAEnabled, recoveryEmail: secRecEmail };
    if (secNewPass) updated.password = secNewPass;
    saveAdminCreds(updated);
    showSecMsg("success","✅ Security settings saved");
    setSecOldPass(""); setSecNewPass(""); setSecConfPass("");
    addLog("🔒 Security updated", "Password/2FA settings changed");
  };

  // ── Stats ─────────────────────────────────────────────────────
  const pendingUser = (() => {
    try {
      const raw = localStorage.getItem("ep_user");
      if (raw) { const u = JSON.parse(raw); return u.paymentPending ? u : null; }
    } catch {} return null;
  })();

  const TABS = [
    ["dashboard","📊 Dashboard"],
    ["users","👤 Users"],
    ["payments","💳 Payment"],
    ["plans","📋 Plans"],
    ["security","🔒 Security"],
    ["log","📋 Log"],
  ];

  const Card = ({ children, style={} }) => (
    <div style={{ background:"var(--surf)", border:"1px solid var(--border)", borderRadius:18, padding:"16px", boxShadow:"var(--shadow-card)", ...style }}>
      {children}
    </div>
  );

  const Field = ({ label, value, onChange, type="text", placeholder="", hint="" }) => (
    <div style={{ marginBottom:12 }}>
      <label style={{ fontSize:12, fontWeight:700, color:"var(--text-2)", display:"block", marginBottom:5 }}>{label}</label>
      <input type={type} defaultValue={value} onBlur={e => onChange(e.target.value)}
        placeholder={placeholder}
        style={{ width:"100%", padding:"10px 12px", borderRadius:12, border:"1.5px solid var(--border)", fontSize:13, background:"var(--surf-2)", color:"var(--text)", boxSizing:"border-box" }} />
      {hint && <div style={{ fontSize:10, color:"var(--text-3)", marginTop:3 }}>{hint}</div>}
    </div>
  );

  return (
    <div style={{ minHeight:"100dvh", background:"var(--bg)", padding:"16px", maxWidth:680, margin:"0 auto", animation:"fadeUp .3s ease" }}>

      {/* Header */}
      <div style={{ display:"flex", gap:10, alignItems:"center", marginBottom:18 }}>
        <button onClick={() => dispatch({ type:"SET_SCREEN", payload:"home" })}
          style={{ width:36, height:36, borderRadius:12, background:"var(--surf-2)", border:"1px solid var(--border)", cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", color:"var(--text-2)", flexShrink:0 }}>
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><polyline points="15,18 9,12 15,6"/></svg>
        </button>
        <div style={{ flex:1 }}>
          <h2 style={{ fontFamily:"'Poppins',sans-serif", fontSize:20, fontWeight:700, color:"var(--text)", margin:0 }}>⚙️ Admin Panel</h2>
          <div style={{ fontSize:11, color:"var(--text-3)", marginTop:2 }}>EngPath · {ADMIN_EMAIL}</div>
        </div>
        {saved && <div style={{ fontSize:12, color:"var(--green)", fontWeight:700, padding:"5px 12px", borderRadius:999, background:"var(--green-soft)", border:"1px solid var(--green-border)" }}>✅ Saved</div>}
      </div>

      {/* Tab bar */}
      <div style={{ display:"flex", gap:5, marginBottom:18, overflowX:"auto", paddingBottom:2, WebkitOverflowScrolling:"touch" }}>
        {TABS.map(([id,label]) => (
          <button key={id} onClick={() => setTab(id)}
            style={{ padding:"8px 12px", borderRadius:12, border:"none", cursor:"pointer", fontSize:11, fontWeight:700, whiteSpace:"nowrap", flexShrink:0, transition:"all .18s",
              background: tab===id ? "var(--accent)" : "var(--surf-2)",
              color:      tab===id ? "#fff" : "var(--text-2)",
              boxShadow:  tab===id ? "0 3px 10px rgba(108,92,231,.3)" : "none" }}>
            {label}
          </button>
        ))}
      </div>

      {/* ── DASHBOARD ── */}
      {tab==="dashboard" && (
        <div style={{ display:"flex", flexDirection:"column", gap:12 }}>
          {/* Stats row */}
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr", gap:10 }}>
            {[
              { icon:"👤", label:"Current User", value: state.user?.email?.split("@")[0] || "—" },
              { icon:"⭐", label:"Pro Status",   value: isActivePro(state.user) ? "Active" : "Free", col: isActivePro(state.user) ? "var(--green)" : "var(--text-3)" },
              { icon:"📅", label:"Expires",      value: state.user?.expiryDate ? new Date(state.user.expiryDate).toLocaleDateString("en-GB",{day:"2-digit",month:"short",year:"2-digit"}) : "—" },
            ].map(s => (
              <Card key={s.label} style={{ textAlign:"center", padding:"12px 8px" }}>
                <div style={{ fontSize:20, marginBottom:4 }}>{s.icon}</div>
                <div style={{ fontFamily:"'Poppins',sans-serif", fontSize:12, fontWeight:700, color:s.col||"var(--text)", overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{s.value}</div>
                <div style={{ fontSize:10, color:"var(--text-3)", marginTop:2 }}>{s.label}</div>
              </Card>
            ))}
          </div>

          {/* Pending payment alert */}
          {pendingUser && (
            <Card style={{ border:"1.5px solid var(--gold-border)", background:"var(--gold-soft)" }}>
              <div style={{ display:"flex", alignItems:"center", gap:10 }}>
                <span style={{ fontSize:26 }}>⏳</span>
                <div style={{ flex:1 }}>
                  <div style={{ fontSize:13, fontWeight:800, color:"var(--gold)", marginBottom:2 }}>Payment Pending!</div>
                  <div style={{ fontSize:12, color:"var(--text-2)" }}>{pendingUser.email} · Plan: {pendingUser.pendingPlan || "unknown"}</div>
                </div>
                <button onClick={() => { setTab("users"); setSearch(pendingUser.email); }}
                  style={{ padding:"8px 14px", borderRadius:12, background:"var(--gold)", border:"none", cursor:"pointer", fontSize:12, fontWeight:700, color:"#fff" }}>
                  Activate →
                </button>
              </div>
            </Card>
          )}

          {/* How to activate guide */}
          <Card>
            <div style={{ fontFamily:"'Poppins',sans-serif", fontSize:14, fontWeight:700, color:"var(--text)", marginBottom:12 }}>📋 How to Activate Pro</div>
            {[
              { step:"1", icon:"📲", text:"User pays and sends screenshot on WhatsApp" },
              { step:"2", icon:"✅", text:"You verify the payment screenshot" },
              { step:"3", icon:"👤", text:"Go to Users tab → enter their email → Search" },
              { step:"4", icon:"⭐", text:"Select plan (6 Month / 1 Year) → tap Activate" },
              { step:"5", icon:"🎉", text:"Pro is instantly active for that user" },
            ].map(s => (
              <div key={s.step} style={{ display:"flex", gap:10, alignItems:"flex-start", padding:"8px 0", borderBottom:"1px solid var(--border)" }}>
                <div style={{ width:24, height:24, borderRadius:"50%", background:"linear-gradient(135deg,var(--accent),var(--blue))", display:"flex", alignItems:"center", justifyContent:"center", fontSize:11, fontWeight:900, color:"#fff", flexShrink:0 }}>{s.step}</div>
                <span style={{ fontSize:12 }}>{s.icon}</span>
                <div style={{ fontSize:13, color:"var(--text-2)", lineHeight:1.5, flex:1 }}>{s.text}</div>
              </div>
            ))}
          </Card>

          {/* Quick links */}
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10 }}>
            <button onClick={() => setTab("users")} style={{ padding:"14px", borderRadius:16, background:"linear-gradient(135deg,var(--accent),var(--blue))", border:"none", cursor:"pointer", fontSize:13, fontWeight:700, color:"#fff" }}>
              👤 Manage Users
            </button>
            <button onClick={() => setTab("payments")} style={{ padding:"14px", borderRadius:16, background:"linear-gradient(135deg,var(--green),#16a34a)", border:"none", cursor:"pointer", fontSize:13, fontWeight:700, color:"#fff" }}>
              💳 Payment Setup
            </button>
          </div>
        </div>
      )}

      {/* ── USERS TAB ── */}
      {tab==="users" && (
        <div style={{ display:"flex", flexDirection:"column", gap:12 }}>
          <Card>
            <div style={{ fontFamily:"'Poppins',sans-serif", fontSize:14, fontWeight:700, color:"var(--text)", marginBottom:12 }}>🔍 Find User</div>
            <div style={{ display:"flex", gap:8 }}>
              <input value={searchEmail} onChange={e => { setSearch(e.target.value); setUserFound(null); }}
                onKeyDown={e => e.key==="Enter" && findUser()}
                placeholder="user@email.com" type="email"
                style={{ flex:1, padding:"11px 14px", borderRadius:14, border:"1.5px solid var(--border)", fontSize:14, background:"var(--surf-2)", color:"var(--text)", outline:"none" }} />
              <button onClick={findUser}
                style={{ padding:"11px 20px", borderRadius:14, background:"linear-gradient(135deg,var(--accent),var(--blue))", border:"none", cursor:"pointer", fontSize:13, fontWeight:700, color:"#fff", flexShrink:0 }}>
                Search
              </button>
            </div>
          </Card>

          {/* Search result */}
          {userFound === "not_found" && (
            <Card style={{ textAlign:"center", padding:"20px" }}>
              <div style={{ fontSize:32, marginBottom:8 }}>🔍</div>
              <div style={{ fontSize:14, fontWeight:700, color:"var(--red)", marginBottom:4 }}>User not found</div>
              <div style={{ fontSize:12, color:"var(--text-3)" }}>The user must log in at least once on this device.</div>
            </Card>
          )}

          {userFound && userFound !== "not_found" && (
            <Card>
              {/* User info */}
              <div style={{ display:"flex", gap:12, alignItems:"center", marginBottom:16, paddingBottom:14, borderBottom:"1px solid var(--border)" }}>
                <div style={{ width:48, height:48, borderRadius:16, background:"linear-gradient(135deg,var(--accent),var(--blue))", display:"flex", alignItems:"center", justifyContent:"center", fontSize:20, fontWeight:700, color:"#fff", flexShrink:0 }}>
                  {(userFound.name||"U")[0].toUpperCase()}
                </div>
                <div style={{ flex:1, minWidth:0 }}>
                  <div style={{ fontFamily:"'Poppins',sans-serif", fontSize:15, fontWeight:700, color:"var(--text)", marginBottom:2, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{userFound.name || "Unknown"}</div>
                  <div style={{ fontSize:12, color:"var(--text-3)", marginBottom:4, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{userFound.email}</div>
                  <div style={{ display:"flex", gap:6, flexWrap:"wrap" }}>
                    <span style={{ fontSize:10, fontWeight:700, padding:"2px 8px", borderRadius:999, background: userFound.isPro ? "rgba(34,197,94,.1)" : "var(--surf-2)", color: userFound.isPro ? "var(--green)" : "var(--text-3)", border: userFound.isPro ? "1px solid rgba(34,197,94,.3)" : "1px solid var(--border)" }}>
                      {userFound.isPro ? "⭐ PRO" : "🆓 FREE"}
                    </span>
                    {userFound.expiryDate && (
                      <span style={{ fontSize:10, padding:"2px 8px", borderRadius:999, background:"var(--blue-soft)", color:"var(--blue)", border:"1px solid var(--blue-border)" }}>
                        Until {new Date(userFound.expiryDate).toLocaleDateString()}
                      </span>
                    )}
                    {userFound.paymentPending && (
                      <span style={{ fontSize:10, fontWeight:700, padding:"2px 8px", borderRadius:999, background:"var(--gold-soft)", color:"var(--gold)", border:"1px solid var(--gold-border)" }}>
                        ⏳ Payment Pending
                      </span>
                    )}
                    <span style={{ fontSize:10, padding:"2px 8px", borderRadius:999, background:"var(--surf-2)", color:"var(--text-3)", border:"1px solid var(--border)" }}>
                      Level: {userFound.level || "B1"}
                    </span>
                    <span style={{ fontSize:10, padding:"2px 8px", borderRadius:999, background:"var(--surf-2)", color:"var(--text-3)", border:"1px solid var(--border)" }}>
                      XP: {(userFound.xp||0).toLocaleString()}
                    </span>
                  </div>
                </div>
              </div>

              {/* Plan selector */}
              {!userFound.isPro && (
                <>
                  <div style={{ fontSize:12, fontWeight:700, color:"var(--text-2)", marginBottom:8 }}>Select Plan to Activate:</div>
                  <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:8, marginBottom:12 }}>
                    {[["sixMonth","6 Months","180 days"],["oneYear","1 Year ⭐","365 days"]].map(([key,label,sub])=>(
                      <button key={key} onClick={()=>setPlanSel(key)}
                        style={{ padding:"12px", borderRadius:14, border:`2px solid ${planSel===key?"var(--accent)":"var(--border)"}`, background:planSel===key?"var(--accent-soft)":"var(--surf-2)", cursor:"pointer", textAlign:"center", transition:"all .2s" }}>
                        <div style={{ fontSize:13, fontWeight:700, color:planSel===key?"var(--accent)":"var(--text)" }}>{label}</div>
                        <div style={{ fontSize:10, color:"var(--text-3)", marginTop:2 }}>{sub}</div>
                      </button>
                    ))}
                  </div>
                  <button onClick={() => activateUser(planSel)}
                    style={{ width:"100%", padding:"14px", borderRadius:16, background:"linear-gradient(135deg,var(--green),#16a34a)", border:"none", cursor:"pointer", fontSize:15, fontWeight:800, color:"#fff", boxShadow:"0 6px 20px rgba(34,197,94,.4)", marginBottom:8 }}>
                    ⭐ Activate Pro — {planSel==="sixMonth"?"6 Months":"1 Year"}
                  </button>
                </>
              )}

              {userFound.isPro && (
                <div style={{ marginBottom:12 }}>
                  <div style={{ padding:"12px 14px", background:"var(--green-soft)", border:"1px solid var(--green-border)", borderRadius:14, textAlign:"center", marginBottom:10 }}>
                    <div style={{ fontSize:14, fontWeight:800, color:"var(--green)", marginBottom:3 }}>✅ Pro is Active</div>
                    <div style={{ fontSize:12, color:"var(--text-2)" }}>Expires: {userFound.expiryDate ? new Date(userFound.expiryDate).toLocaleDateString("en-GB",{day:"2-digit",month:"long",year:"numeric"}) : "Never"}</div>
                  </div>
                  <button onClick={deactivateUser}
                    style={{ width:"100%", padding:"12px", borderRadius:14, background:"var(--red-soft)", border:"1.5px solid var(--red-border)", cursor:"pointer", fontSize:13, fontWeight:700, color:"var(--red)" }}>
                    🚫 Remove Pro Access
                  </button>
                </div>
              )}
            </Card>
          )}

          {/* Help */}
          <div style={{ padding:"12px 14px", background:"var(--accent-soft)", border:"1px solid var(--accent-border)", borderRadius:14, fontSize:12, color:"var(--accent)", lineHeight:1.7 }}>
            💡 <strong>Note:</strong> The user must have logged in on this device at least once for their data to be found here. In a production server setup, you would search a real database.
          </div>
        </div>
      )}

      {/* ── PAYMENT SETTINGS TAB ── */}
      {tab==="payments" && (
        <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
          <Card>
            <div style={{ fontFamily:"'Poppins',sans-serif", fontSize:14, fontWeight:700, color:"var(--text)", marginBottom:14 }}>💳 Payment Details</div>
            {/* Payment method toggles */}
            <div style={{ marginBottom:16, padding:"12px 14px", background:"var(--surf-2)", border:"1px solid var(--border)", borderRadius:14 }}>
              <div style={{ fontSize:12, fontWeight:800, color:"var(--text-2)", marginBottom:10, textTransform:"uppercase", letterSpacing:".06em" }}>Payment Methods ON/OFF</div>
              {[
                { key:"showBankTransfer", icon:"🏦", label:"Bank Transfer"   },
                { key:"showUPI",          icon:"📱", label:"UPI / GPay"      },
                { key:"showQRCode",       icon:"📷", label:"QR Code"         },
                { key:"showWhatsApp",     icon:"📲", label:"WhatsApp Contact" },
              ].map(t => (
                <div key={t.key} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"9px 0", borderBottom:"1px solid var(--border)" }}>
                  <div style={{ display:"flex", gap:8, alignItems:"center" }}>
                    <span style={{ fontSize:16 }}>{t.icon}</span>
                    <span style={{ fontSize:13, fontWeight:600, color:"var(--text)" }}>{t.label}</span>
                  </div>
                  <button onClick={() => updateCfg(t.key, !(cfg[t.key]??true))}
                    style={{ width:46, height:26, borderRadius:999, background:(cfg[t.key]??true)?"var(--green)":"var(--border-2)", border:"none", cursor:"pointer", position:"relative", transition:"background .25s", flexShrink:0 }}>
                    <div style={{ position:"absolute", top:3, left:(cfg[t.key]??true)?22:3, width:20, height:20, borderRadius:"50%", background:"#fff", transition:"left .25s", boxShadow:"0 1px 4px rgba(0,0,0,.2)" }} />
                  </button>
                </div>
              ))}
            </div>

            {[
              { key:"whatsapp",    label:"📲 WhatsApp Number", placeholder:"971553156160", hint:"Without + · Users send payment proof here", show: true },
              { key:"bankName",    label:"🏦 Bank Name",       placeholder:"First Abu Dhabi Bank",         show: cfg.showBankTransfer??true },
              { key:"bankIBAN",    label:"IBAN",               placeholder:"AE070330000010230491222",       show: cfg.showBankTransfer??true },
              { key:"bankHolder",  label:"Account Holder",     placeholder:"EngPath Technologies LLC",      show: cfg.showBankTransfer??true },
              { key:"upiId",       label:"📱 UPI ID",          placeholder:"engpath@upi",                   show: cfg.showUPI??false, hint:"e.g. yourname@paytm or phone@upi" },
              { key:"upiName",     label:"UPI Account Name",   placeholder:"EngPath Technologies",          show: cfg.showUPI??false },
              { key:"qrImage",     label:"📷 QR Code Image URL",placeholder:"https://...",                  show: cfg.showQRCode??false, hint:"Upload your QR image and paste the URL here" },
              { key:"paymentNote", label:"📋 Payment Note",    placeholder:"Send screenshot to WhatsApp",   show: true },
            ].filter(f=>f.show).map(field=>(
              <div key={field.key} style={{ marginBottom:12 }}>
                <label style={{ fontSize:12, fontWeight:700, color:"var(--text-2)", display:"block", marginBottom:5 }}>{field.label}</label>
                {field.key==="paymentNote" ? (
                  <textarea defaultValue={cfg[field.key]||""} onBlur={e=>updateCfg(field.key,e.target.value)}
                    rows={2} placeholder={field.placeholder}
                    style={{ width:"100%", padding:"10px 12px", borderRadius:12, border:"1.5px solid var(--border)", fontSize:13, background:"var(--surf-2)", color:"var(--text)", resize:"none", boxSizing:"border-box" }}/>
                ) : (
                  <input defaultValue={cfg[field.key]||""} onBlur={e=>updateCfg(field.key,e.target.value)}
                    placeholder={field.placeholder}
                    style={{ width:"100%", padding:"10px 12px", borderRadius:12, border:"1.5px solid var(--border)", fontSize:13, background:"var(--surf-2)", color:"var(--text)", boxSizing:"border-box" }}/>
                )}
                {field.hint && <div style={{ fontSize:10, color:"var(--text-3)", marginTop:3 }}>{field.hint}</div>}
              </div>
            ))}
          </Card>
        </div>
      )}

      {/* ── PLANS TAB ── */}
      {tab==="plans" && (
        <div style={{ display:"flex", flexDirection:"column", gap:12 }}>
          {Object.entries(cfg.plans||{}).map(([key,plan])=>(
            <Card key={key}>
              <div style={{ fontFamily:"'Poppins',sans-serif", fontSize:14, fontWeight:700, color:"var(--text)", marginBottom:12 }}>{key==="sixMonth"?"📅 6-Month Plan":"🏆 1-Year Plan"}</div>
              <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10 }}>
                <div>
                  <label style={{ fontSize:11, fontWeight:700, color:"var(--text-3)", display:"block", marginBottom:4 }}>Price (AED)</label>
                  <input type="number" defaultValue={plan.price||49} onBlur={e=>updatePlan(key,"price",Number(e.target.value))}
                    style={{ width:"100%", padding:"9px 12px", borderRadius:10, border:"1.5px solid var(--border)", fontSize:14, fontWeight:700, background:"var(--surf-2)", color:"var(--text)", boxSizing:"border-box" }}/>
                </div>
                <div>
                  <label style={{ fontSize:11, fontWeight:700, color:"var(--text-3)", display:"block", marginBottom:4 }}>Days</label>
                  <input type="number" defaultValue={plan.days||180} onBlur={e=>updatePlan(key,"days",Number(e.target.value))}
                    style={{ width:"100%", padding:"9px 12px", borderRadius:10, border:"1.5px solid var(--border)", fontSize:14, fontWeight:700, background:"var(--surf-2)", color:"var(--text)", boxSizing:"border-box" }}/>
                </div>
              </div>
            </Card>
          ))}
        </div>
      )}

      {/* ── SECURITY TAB ── */}
      {tab==="security" && (
        <div style={{ display:"flex", flexDirection:"column", gap:12 }}>
          <Card>
            <div style={{ fontFamily:"'Poppins',sans-serif", fontSize:14, fontWeight:700, color:"var(--text)", marginBottom:14 }}>🔑 Change Admin Password</div>
            {[
              { label:"New Password",     value:secNewPass,  set:setSecNewPass },
              { label:"Confirm Password", value:secConfPass, set:setSecConfPass },
            ].map(f=>(
              <div key={f.label} style={{ marginBottom:12 }}>
                <label style={{ fontSize:12, fontWeight:700, color:"var(--text-2)", display:"block", marginBottom:5 }}>{f.label}</label>
                <input type="password" value={f.value} onChange={e=>f.set(e.target.value)} placeholder="••••••••"
                  style={{ width:"100%", padding:"10px 12px", borderRadius:12, border:"1.5px solid var(--border)", fontSize:13, background:"var(--surf-2)", color:"var(--text)", boxSizing:"border-box" }}/>
              </div>
            ))}
            <div style={{ marginBottom:14 }}>
              <label style={{ fontSize:12, fontWeight:700, color:"var(--text-2)", display:"block", marginBottom:5 }}>Recovery Email</label>
              <input type="email" value={secRecEmail} onChange={e=>setSecRecEmail(e.target.value)}
                style={{ width:"100%", padding:"10px 12px", borderRadius:12, border:"1.5px solid var(--border)", fontSize:13, background:"var(--surf-2)", color:"var(--text)", boxSizing:"border-box" }}/>
            </div>
          </Card>

          <Card>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center" }}>
              <div>
                <div style={{ fontSize:14, fontWeight:700, color:"var(--text)" }}>🔐 Two-Factor Authentication</div>
                <div style={{ fontSize:11, color:"var(--text-3)", marginTop:2 }}>OTP required every admin login</div>
              </div>
              <button onClick={()=>setTwoFA(t=>!t)}
                style={{ width:50, height:28, borderRadius:999, background:twoFAEnabled?"var(--green)":"var(--border-2)", border:"none", cursor:"pointer", position:"relative", transition:"background .25s", flexShrink:0 }}>
                <div style={{ position:"absolute", top:3, left:twoFAEnabled?24:3, width:22, height:22, borderRadius:"50%", background:"#fff", transition:"left .25s", boxShadow:"0 2px 6px rgba(0,0,0,.2)" }}/>
              </button>
            </div>
          </Card>

          {secMsg.text && (
            <div style={{ padding:"11px 14px", borderRadius:12, background:secMsg.type==="success"?"var(--green-soft)":"var(--red-soft)", border:`1px solid ${secMsg.type==="success"?"var(--green-border)":"var(--red-border)"}`, fontSize:13, fontWeight:600, color:secMsg.type==="success"?"var(--green)":"var(--red)" }}>
              {secMsg.text}
            </div>
          )}

          <button onClick={saveSecurity}
            style={{ width:"100%", padding:"14px", borderRadius:16, background:"linear-gradient(135deg,var(--accent),var(--blue))", border:"none", cursor:"pointer", fontSize:14, fontWeight:700, color:"#fff", boxShadow:"0 4px 14px rgba(108,92,231,.3)" }}>
            💾 Save Security Settings
          </button>
        </div>
      )}

      {/* ── ACTIVITY LOG TAB ── */}
      {tab==="log" && (
        <div>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:12 }}>
            <div style={{ fontFamily:"'Poppins',sans-serif", fontSize:14, fontWeight:700, color:"var(--text)" }}>📋 Activity Log</div>
            <button onClick={()=>{setActLog([]);localStorage.removeItem("ep_admin_log");}} style={{ fontSize:11, fontWeight:700, color:"var(--red)", background:"var(--red-soft)", border:"1px solid var(--red-border)", borderRadius:20, padding:"5px 12px", cursor:"pointer" }}>Clear</button>
          </div>
          {actLog.length === 0 ? (
            <Card style={{ textAlign:"center", padding:"28px" }}>
              <div style={{ fontSize:32, marginBottom:8 }}>📋</div>
              <div style={{ fontSize:14, color:"var(--text-3)" }}>No activity yet</div>
            </Card>
          ) : (
            <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
              {actLog.map((entry, i) => (
                <Card key={i} style={{ padding:"12px 14px" }}>
                  <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", gap:8 }}>
                    <div style={{ flex:1 }}>
                      <div style={{ fontSize:13, fontWeight:700, color:"var(--text)", marginBottom:2 }}>{entry.action}</div>
                      <div style={{ fontSize:12, color:"var(--text-3)" }}>{entry.detail}</div>
                    </div>
                    <div style={{ fontSize:10, color:"var(--text-3)", flexShrink:0, textAlign:"right" }}>{entry.time}</div>
                  </div>
                </Card>
              ))}
            </div>
          )}
        </div>
      )}

    </div>
  );
});
/* ════════════════════════════════════════════════════════════════
   APP ROOT
════════════════════════════════════════════════════════════════ */
export default function App() {
  const [state, dispatch] = useReducer(reducer, initialState);
  const nav         = useCallback(s => dispatch({ type: "SET_SCREEN", payload: s }), []);

  // Check subscription expiry on every mount
  useEffect(() => { dispatch({ type:"CHECK_EXPIRY" }); }, []);

  // ✅ AUDIO FIX: unlock mobile audio pipeline on first user interaction
  useEffect(() => {
    const handler = () => { unlockAudio(); };
    window.addEventListener("touchstart", handler, { once: true, passive: true });
    window.addEventListener("click",      handler, { once: true, passive: true });
    return () => {
      window.removeEventListener("touchstart", handler);
      window.removeEventListener("click",      handler);
    };
  }, []);

  // ✅ FIX #6: Re-check expiry every 60 seconds - catches mid-session expiry
  useEffect(() => {
    const interval = setInterval(() => {
      dispatch({ type:"CHECK_EXPIRY" });
    }, 60_000);
    return () => clearInterval(interval);
  }, []);
  const removeToast = useCallback(id => dispatch({ type: "REM_TOAST", payload: id }), []);
  const theme       = state.settings.theme;

  const pageProps = useMemo(() => ({ state, dispatch }), [state]);

  const page = useMemo(() => {
    switch (state.screen) {
      case "login":        return <LoginPage   dispatch={dispatch} />;
      case "upgrade":      return <UpgradePage dispatch={dispatch} state={state} />;
      case "home":         return <Home         {...pageProps} />;
      case "practice":     return <Practice     {...pageProps} />;
      case "conversation": return <Conversation {...pageProps} />;
      case "vocabulary":   return <Vocabulary   {...pageProps} />;
      case "leveltest":    return <LevelTest     {...pageProps} />;
      case "grammar":      return <Grammar      {...pageProps} />;
      case "dictionary":   return <Dictionary   {...pageProps} />;
      case "chatbot":      return <Chatbot      {...pageProps} />;
      case "settings":     return <Settings     {...pageProps} />;
      case "howto":        return <HowToUsePage  dispatch={dispatch} />;
        case "terms":        return <TermsPage    dispatch={dispatch} />;
        case "privacy":      return <PrivacyPage  dispatch={dispatch} />;
        case "contact":      return <ContactPage  dispatch={dispatch} />;
      case "faq":          return <FaqPage        dispatch={dispatch} state={state} />;
      case "admin": {
        // ✅ ROLE-BASED: requires matching admin email AND a valid 2FA session token
        if (!isAdminUser(state.user)) {
          setTimeout(() => dispatch({ type: "SET_SCREEN", payload: "home" }), 0);
          return <Home {...pageProps} />;
        }
        return <AdminPanel state={state} dispatch={dispatch} />;
      }
      default:             return <Home         {...pageProps} />;
    }
  }, [state.screen, pageProps]);

  return (
    <>
      {/* Inject CSS variables based on theme */}
      <style>{`
        ${GLOBAL_CSS}
        :root { ${theme === "dark" ? DARK_VARS : LIGHT_VARS} }
        html, body {
          overscroll-behavior: none;
          -webkit-overflow-scrolling: touch;
          touch-action: manipulation;
          -webkit-tap-highlight-color: transparent;
          font-family: 'Inter', sans-serif;
        }
        * { box-sizing: border-box; }
        textarea, input, select, button { font-family: inherit; }
        button { -webkit-appearance: none; appearance: none; }
      `}</style>

      <div style={{
        height:         "100dvh",
        display:        "flex",
        flexDirection:  "column",
        background:     "var(--bg)",
        color:          "var(--text)",
        overflow:       "hidden",
      }}>
        {/* Toast notifications */}
        <div style={{
          position: "fixed", bottom: 100, right: 14, zIndex: 200,
          display: "flex", flexDirection: "column", gap: 8, alignItems: "flex-end",
        }}>
          {state.toasts.map(t => (
            <Toast key={t.id} toast={t} onRemove={removeToast} />
          ))}
        </div>

        {/* Top bar - hidden on auth screens */}
        {!["login","upgrade","howto","faq","admin","terms","privacy","contact"].includes(state.screen) && (
          <TopBar screen={state.screen} onNav={nav} user={state.user} />
        )}

        {/* Main content - scrolls independently */}
        <div style={{
          flex:                      1,
          overflowY:                 "auto",
          overflowX:                 "hidden",
          /* chatbot manages its own height; all other screens need padding for floating nav */
          paddingBottom:             ["chatbot","login","upgrade","howto","faq","admin","terms","privacy","contact"].includes(state.screen) ? 0 : 96,
          WebkitOverflowScrolling:   "touch",
        }}>
          {page}
        </div>

        {/* Bottom navigation - hidden on auth screens */}
        {!["login","upgrade","howto","faq","admin","terms","privacy","contact"].includes(state.screen) && (
          <BottomNav screen={state.screen} onNav={nav} />
        )}
      </div>
    </>
  );
}

